import { Elysia, t } from "elysia";
import { BackupService } from "../../services/backup/BackupService";
import { BackupScheduler } from "../../services/backup/BackupScheduler";

const backupService = new BackupService();
export const backupScheduler = new BackupScheduler();

export const backupRoutes = new Elysia({ prefix: "/backup" })
  .get("/list", async () => {
    try {
      const backups = await backupService.listBackups();
      return { success: true, backups };
    } catch (err: any) {
      return { success: false, message: err.message };
    }
  })
  .post("/create", async ({ body }) => {
    try {
      const result = await backupService.createBackup(body.password);
      return { success: true, result };
    } catch (err: any) {
      return { success: false, message: err.message };
    }
  }, {
    body: t.Object({ password: t.String() })
  })
  .post("/restore", async ({ body }) => {
    try {
      const result = await backupService.restoreBackup(body.filename, body.password);
      return { success: true, result };
    } catch (err: any) {
      return { success: false, message: err.message };
    }
  }, {
    body: t.Object({ filename: t.String(), password: t.String() })
  })
  .get("/download/:filename", async ({ params, set }) => {
    try {
      const path = await backupService.exportBackup(params.filename);
      // Elysia serves files directly by returning Bun.file
      return Bun.file(path);
    } catch (err: any) {
      set.status = 404;
      return { success: false, message: "Backup no encontrado." };
    }
  })
  .post("/validate", async ({ body }) => {
    try {
      const result = await backupService.validateBackup(body.filename, body.password);
      return { success: true, result };
    } catch (err: any) {
      return { success: false, message: err.message };
    }
  }, {
    body: t.Object({ filename: t.String(), password: t.String() })
  })
  .get("/status", async () => {
    try {
      const info = await backupScheduler.getLastBackupInfo();
      const next = await backupScheduler.getNextBackupTime();
      return { success: true, info, next };
    } catch (err: any) {
      return { success: false, message: err.message };
    }
  })
  .put("/schedule", async ({ body }) => {
    try {
      await backupScheduler.setSchedule(body.hourUTC);
      return { success: true, message: "Schedule updated." };
    } catch (err: any) {
      return { success: false, message: err.message };
    }
  }, {
    body: t.Object({ hourUTC: t.Number() })
  });

// ============================================================
// MIGRATION RUNNER — PostgreSQL 16
// Uses Drizzle Kit's official migrator for PostgreSQL.
// Applies schema migrations from ./drizzle/migrations/
// Then applies PL/pgSQL triggers as raw SQL.
// ============================================================

import { migrate } from "drizzle-orm/postgres-js/migrator";
import postgres from "postgres";
import { drizzle } from "drizzle-orm/postgres-js";
import { db, sql } from "./connection.ts";
import { TRIGGERS } from "./triggers.ts";
import { INDEXES } from "./indexes.ts";
import { join, dirname } from "path";
import { fileURLToPath } from "url";

const __filename = fileURLToPath(import.meta.url);
const __dirname = dirname(__filename);

export async function runMigrations(): Promise<void> {
  console.log("[MIGRATE] Starting PostgreSQL migration runner...");

  const connectionString = process.env.DATABASE_ADMIN_URL ?? process.env.DATABASE_URL;
  const migrationClient = postgres(connectionString as string, { max: 1 });
  const migrationDb = drizzle(migrationClient);

  // Run Drizzle Kit migrations
  await migrate(migrationDb, {
    migrationsFolder: join(__dirname, "../../drizzle/migrations"),
  });

  console.log("[MIGRATE] Schema migrations applied.");

  // Apply indexes (idempotent — CREATE INDEX IF NOT EXISTS)
  console.log("[MIGRATE] Applying indexes...");
  for (const idx of INDEXES) {
    await migrationDb.execute(sql.raw(idx));
  }

  // Apply PL/pgSQL triggers (idempotent — CREATE OR REPLACE)
  console.log("[MIGRATE] Applying PL/pgSQL triggers...");
  for (const trg of TRIGGERS) {
    await migrationDb.execute(sql.raw(trg));
  }

  console.log("[MIGRATE] Done. Schema, indexes and triggers are up to date.");
}

// ── DIRECT RUN ───────────────────────────────────────────────
// Allow: bun run src/db/migrate.ts
if (import.meta.main) {
  runMigrations()
    .then(() => process.exit(0))
    .catch((err) => {
      console.error("[MIGRATE] ❌ Fatal error:", err);
      process.exit(1);
    });
}

// ============================================================
// BANK ACCOUNTS SCHEMA — PostgreSQL 16
// ============================================================

import { pgTable, text, boolean, integer, numeric, timestamp } from "drizzle-orm/pg-core";
import { companies } from "./system.schema.ts";
import { chartOfAccounts } from "./accounting.schema.ts";

export const bankAccounts = pgTable("bank_accounts", {
  id: text("id").primaryKey(),
  companyId: text("company_id").notNull().references(() => companies.id),
  accountName: text("account_name").notNull(),
  bankName: text("bank_name").notNull(),
  accountNumber: text("account_number"),
  accountType: text("account_type").notNull().default("checking"),
  // balance stored as integer cents to avoid floating point issues
  balance: integer("balance").notNull().default(0),
  glAccountId: text("gl_account_id").references(() => chartOfAccounts.id),
  isActive: boolean("is_active").notNull().default(true),
  createdAt: timestamp("created_at", { withTimezone: true }).notNull(),
  updatedAt: timestamp("updated_at", { withTimezone: true }).notNull(),
});

// ============================================================
// SYSTEM INFRASTRUCTURE SCHEMA — PostgreSQL 16
// Group A — 10 tables: security, multitenancy, audit
// ============================================================

import {
  pgTable,
  text,
  boolean,
  integer,
  timestamp,
  uniqueIndex,
  index,
} from "drizzle-orm/pg-core";
import { sql } from "drizzle-orm";

// ─────────────────────────────────────────────────────────────
// 1. SYSTEM_CONFIG
// Single-row global installation configuration.
// ─────────────────────────────────────────────────────────────
export const systemConfig = pgTable("system_config", {
  id: text("id").primaryKey(), // UUID v4
  schemaVersion: text("schema_version").notNull(),
  appName: text("app_name").notNull(),
  licenseKey: text("license_key"),
  maxCompanies: integer("max_companies").default(999).notNull(),
  maintenanceMode: boolean("maintenance_mode").default(false).notNull(),
  backupScheduleHour: integer("backup_schedule_hour"), // nullable
  createdAt: timestamp("created_at", { withTimezone: true }).notNull(),
  updatedAt: timestamp("updated_at", { withTimezone: true }).notNull(),
});

// ─────────────────────────────────────────────────────────────
// 2. COMPANIES
// Each row = fully isolated tenant.
// ─────────────────────────────────────────────────────────────
export const companies = pgTable("companies", {
  id: text("id").primaryKey(),
  legalName: text("legal_name").notNull(),
  tradeName: text("trade_name"),
  ein: text("ein").unique(),
  address: text("address"),
  city: text("city"),
  state: text("state"),
  zipCode: text("zip_code"),
  phone: text("phone"),
  email: text("email"),
  fiscalYearStart: text("fiscal_year_start").notNull(), // MM-DD e.g. "01-01"
  currency: text("currency").default("USD").notNull(),
  isActive: boolean("is_active").default(true).notNull(),
  createdAt: timestamp("created_at", { withTimezone: true }).notNull(),
  updatedAt: timestamp("updated_at", { withTimezone: true }).notNull(),
});

// ─────────────────────────────────────────────────────────────
// 3. USERS
// Passwords NEVER stored in plain text.
// bcrypt cost 12 = ~300ms per hash (brute-force deterrent).
// After 5 failed consecutive attempts → locked for 30 min.
// ─────────────────────────────────────────────────────────────
export const users = pgTable("users", {
  id: text("id").primaryKey(),
  username: text("username").notNull().unique(),
  email: text("email").notNull().unique(),
  passwordHash: text("password_hash").notNull(), // bcrypt hash, cost 12
  passwordSalt: text("password_salt").notNull(), // random salt per user
  firstName: text("first_name").notNull(),
  lastName: text("last_name").notNull(),
  isSuperAdmin: boolean("is_super_admin").default(false).notNull(),
  isActive: boolean("is_active").default(true).notNull(),
  isLocked: boolean("is_locked").default(false).notNull(),
  failedAttempts: integer("failed_attempts").default(0).notNull(),
  lockedUntil: timestamp("locked_until", { withTimezone: true }),
  lastLoginAt: timestamp("last_login_at", { withTimezone: true }),
  lastLoginIp: text("last_login_ip"),
  mustChangePassword: boolean("must_change_password").default(true).notNull(),
  createdAt: timestamp("created_at", { withTimezone: true }).notNull(),
  updatedAt: timestamp("updated_at", { withTimezone: true }).notNull(),
});

// ─────────────────────────────────────────────────────────────
// 4. ROLES
// 4 system roles (is_system=true) cannot be deleted.
// ─────────────────────────────────────────────────────────────
export const roles = pgTable("roles", {
  id: text("id").primaryKey(),
  name: text("name").notNull().unique(),         // e.g. "super_admin"
  displayName: text("display_name").notNull(),   // e.g. "Super Administrador"
  description: text("description"),
  isSystem: boolean("is_system").default(false).notNull(),
  isActive: boolean("is_active").default(true).notNull(),
  createdAt: timestamp("created_at", { withTimezone: true }).notNull(),
});

// ─────────────────────────────────────────────────────────────
// 5. PERMISSIONS
// Granular module:action pairs.
// ─────────────────────────────────────────────────────────────
export const permissions = pgTable(
  "permissions",
  {
    id: text("id").primaryKey(),
    module: text("module").notNull(),
    action: text("action").notNull(),
    description: text("description"),
    createdAt: timestamp("created_at", { withTimezone: true }).notNull(),
  },
  (table) => ({
    moduleActionUnique: uniqueIndex("uq_permissions_module_action").on(
      table.module,
      table.action
    ),
  })
);

// ─────────────────────────────────────────────────────────────
// 6. ROLE_PERMISSIONS
// ─────────────────────────────────────────────────────────────
export const rolePermissions = pgTable("role_permissions", {
  id: text("id").primaryKey(),
  roleId: text("role_id")
    .notNull()
    .references(() => roles.id),
  permissionId: text("permission_id")
    .notNull()
    .references(() => permissions.id),
  createdAt: timestamp("created_at", { withTimezone: true }).notNull(),
});

// ─────────────────────────────────────────────────────────────
// 7. USER_COMPANY_ROLES
// One active role per user per company (UNIQUE enforced).
// ─────────────────────────────────────────────────────────────
export const userCompanyRoles = pgTable(
  "user_company_roles",
  {
    id: text("id").primaryKey(),
    userId: text("user_id")
      .notNull()
      .references(() => users.id),
    companyId: text("company_id")
      .notNull()
      .references(() => companies.id),
    roleId: text("role_id")
      .notNull()
      .references(() => roles.id),
    isActive: boolean("is_active").default(true).notNull(),
    grantedBy: text("granted_by")
      .notNull()
      .references(() => users.id),
    grantedAt: timestamp("granted_at", { withTimezone: true }).notNull(),
    revokedAt: timestamp("revoked_at", { withTimezone: true }),
  },
  (table) => ({
    userCompanyUnique: uniqueIndex("uq_ucr_user_company").on(
      table.userId,
      table.companyId
    ),
  })
);

// ─────────────────────────────────────────────────────────────
// 8. SESSIONS
// Server-side sessions. No JWT — token lives here.
// ─────────────────────────────────────────────────────────────
export const sessions = pgTable("sessions", {
  id: text("id").primaryKey(),       // UUID v4 = the session token
  userId: text("user_id")
    .notNull()
    .references(() => users.id),
  companyId: text("company_id")
    .references(() => companies.id), // nullable for super_admin global sessions
  ipAddress: text("ip_address").notNull(),
  userAgent: text("user_agent"),
  createdAt: timestamp("created_at", { withTimezone: true }).notNull(),
  expiresAt: timestamp("expires_at", { withTimezone: true }).notNull(),
  lastActiveAt: timestamp("last_active_at", { withTimezone: true }).notNull(),
  isValid: boolean("is_valid").default(true).notNull(),
}, (table) => ({
  idxSessionsUserId:  index("idx_sessions_user_id").on(table.userId),
  idxSessionsValid:   index("idx_sessions_is_valid").on(table.isValid),
}));

// ─────────────────────────────────────────────────────────────
// 9. AUDIT_LOGS
// Immutable forensic ledger. SHA-256 chained entries.
// Only INSERT allowed — no UPDATE/DELETE (enforced by trigger).
// ─────────────────────────────────────────────────────────────
export const auditLogs = pgTable("audit_logs", {
  id: text("id").primaryKey(),
  companyId: text("company_id")
    .references(() => companies.id),
  userId: text("user_id")
    .references(() => users.id),
  sessionId: text("session_id")
    .references(() => sessions.id),
  action: text("action").notNull(),
  module: text("module").notNull(),
  entityType: text("entity_type"),
  entityId: text("entity_id"),
  beforeState: text("before_state"),      // JSON string
  afterState: text("after_state"),        // JSON string
  ipAddress: text("ip_address").notNull(),
  entryHash: text("entry_hash").notNull(),
  prevHash: text("prev_hash").notNull(),
  chainIndex: integer("chain_index").notNull(),
  timestampToken: text("timestamp_token"),
  createdAt: timestamp("created_at", { withTimezone: true }).notNull(),
}, (table) => ({
  idxAuditCompanyCreated: index("idx_audit_company_created").on(table.companyId, table.createdAt),
  idxAuditModule:         index("idx_audit_module").on(table.module),
}));

// ─────────────────────────────────────────────────────────────
// 10. FISCAL_PERIODS
// Controls period open/close/lock lifecycle per company.
// ─────────────────────────────────────────────────────────────
export const fiscalPeriods = pgTable("fiscal_periods", {
  id: text("id").primaryKey(),
  companyId: text("company_id")
    .notNull()
    .references(() => companies.id),
  name: text("name").notNull(), // e.g. "Enero 2026"
  periodType: text("period_type").notNull(), // monthly|quarterly|annual
  startDate: text("start_date").notNull(),   // ISO 8601 date string YYYY-MM-DD
  endDate: text("end_date").notNull(),       // ISO 8601 date string YYYY-MM-DD
  status: text("status").default("open").notNull(), // open|closed|locked
  closedBy: text("closed_by")
    .references(() => users.id),
  closedAt: timestamp("closed_at", { withTimezone: true }),
  createdAt: timestamp("created_at", { withTimezone: true }).notNull(),
});

import { Elysia } from "elysia";
import { db } from "../db/connection.ts";
import { sessions } from "../db/schema/system.schema.ts";
import { eq, and } from "drizzle-orm";

export const authMiddleware = new Elysia({ name: "auth-data" })
  .derive({ as: "global" }, async ({ cookie }) => {
    const sessionId = cookie.session?.value ? String(cookie.session.value) : "";
    if (!sessionId) return { user: null as string | null, companyId: null as string | null, sessionId: "" };

    const dbSession = await db.query.sessions.findFirst({
      where: and(eq(sessions.id, sessionId), eq(sessions.isValid, true))
    });

    if (!dbSession) return { user: null as string | null, companyId: null as string | null, sessionId: "" };

    if (new Date(dbSession.expiresAt) < new Date()) {
      await db.update(sessions).set({ isValid: false }).where(eq(sessions.id, sessionId));
      return { user: null as string | null, companyId: null as string | null, sessionId: "" };
    }

    const now = new Date();
    const expiresAt = new Date(now.getTime() + 8 * 60 * 60 * 1000);
    await db.update(sessions)
      .set({ lastActiveAt: now, expiresAt: expiresAt })
      .where(eq(sessions.id, sessionId));

    return {
      user: dbSession.userId as string,
      companyId: dbSession.companyId ?? null as string | null,
      sessionId
    };
  });

export const requireAuth = ({ user, set }: any) => {
  if (!user) {
    set.status = 401;
    return { error: "Not authenticated" };
  }
};

// ============================================================
// SIMPLE MEMORY-BASED RATE LIMITER MIDDLEWARE
// Prevents brute-force attacks by limiting attempts per IP
// ============================================================

interface RateLimitInfo {
  count: number;
  resetAt: number;
}

const memoryStore = new Map<string, RateLimitInfo>();

/**
 * Creates a rate limiter for a specific route.
 * @param max Max attempts allowed within the window.
 * @param windowMs Time window in milliseconds.
 */
export const loginRateLimiter = (max: number, windowMs: number) => {
  return async ({ request, set }: any) => {
    const ip = request.headers.get("x-forwarded-for") ?? "unknown";
    const now = Date.now();

    let info = memoryStore.get(ip);

    // Cleanup if window expired
    if (info && now > info.resetAt) {
      memoryStore.delete(ip);
      info = undefined;
    }

    if (!info) {
      info = { count: 1, resetAt: now + windowMs };
      memoryStore.set(ip, info);
      return;
    }

    if (info.count >= max) {
      set.status = 429;
      set.headers['Retry-After'] = Math.ceil((info.resetAt - now) / 1000).toString();
      return { 
        error: "Too many login attempts from this IP. Please try again later.",
        retryAfterSeconds: Math.ceil((info.resetAt - now) / 1000)
      };
    }

    info.count++;
  };
};

// Cleanup expired entries every 5 minutes to prevent unbounded memory growth
setInterval(() => {
  const now = Date.now();
  for (const [ip, info] of memoryStore.entries()) {
    if (now > info.resetAt) {
      memoryStore.delete(ip);
    }
  }
}, 5 * 60 * 1000);

import { Elysia } from "elysia";
import { db } from "../db/connection.ts";
import { roles, permissions, rolePermissions } from "../db/schema/system.schema.ts";
import { eq, and } from "drizzle-orm";
import { tenantMiddleware } from "./tenant.middleware.ts";

interface RoleSession {
  roleId: string;
}

export const requirePermission = (moduleName: string, actionName: string) => (app: Elysia) => app
  .use(tenantMiddleware)
  .onBeforeHandle(async ({ roleId }: { roleId: string }) => {
    const role = await db.query.roles.findFirst({
      where: eq(roles.id, roleId)
    });

    if (!role || !role.isActive) {
      return new Response(JSON.stringify({ error: "Role invalid or inactive" }), { status: 403 });
    }

    const targetPermission = await db.query.permissions.findFirst({
      where: and(
        eq(permissions.module, moduleName),
        eq(permissions.action, actionName)
      )
    });

    if (!targetPermission) {
      return new Response(JSON.stringify({ error: `${moduleName}:${actionName} permission not found` }), { status: 403 });
    }

    const hasPerm = await db.query.rolePermissions.findFirst({
      where: and(
        eq(rolePermissions.roleId, roleId),
        eq(rolePermissions.permissionId, targetPermission.id)
      )
    });

    if (!hasPerm) {
      return new Response(JSON.stringify({ error: `${moduleName}:${actionName} denied` }), { status: 403 });
    }
  });

import { Elysia } from "elysia";
import { db } from "../db/connection.ts";
import { userCompanyRoles } from "../db/schema/system.schema.ts";
import { eq, and, isNull } from "drizzle-orm";
import { requireAuth, authMiddleware } from "./auth.middleware.ts";

export const tenantMiddleware = (app: Elysia) => app
  .use(authMiddleware)
  .onBeforeHandle(requireAuth)
  .onBeforeHandle(async ({ user, companyId }: any) => {
    if (!companyId) {
      return new Response(JSON.stringify({ error: "No active company in session" }), { status: 403 });
    }

    const membership = await db.query.userCompanyRoles.findFirst({
      where: and(
        eq(userCompanyRoles.userId, user),
        eq(userCompanyRoles.companyId, companyId),
        eq(userCompanyRoles.isActive, true),
        isNull(userCompanyRoles.revokedAt)
      )
    });

    if (!membership) {
      return new Response(JSON.stringify({ error: "User not in this company" }), { status: 403 });
    }
  })
  .derive(async ({ user, companyId }: any) => {
    if (!companyId) return { roleId: "" };
    const membership = await db.query.userCompanyRoles.findFirst({
      where: and(
        eq(userCompanyRoles.userId, user),
        eq(userCompanyRoles.companyId, companyId),
        eq(userCompanyRoles.isActive, true),
        isNull(userCompanyRoles.revokedAt)
      )
    });
    return {
      roleId: membership?.roleId || ""
    };
  });

// ============================================================
// AI ROUTES
// Endpoint de chat con streaming hacia Ollama local.
// POST /api/ai/chat
// GET  /api/ai/status
// ============================================================

import { Elysia, t } from "elysia";

import { chatWithOllama, buildFinancialContext } from "../services/ai/ai.service.ts";
import { requireAuth, authMiddleware } from "../middleware/auth.middleware.ts";

export const aiRoutes = new Elysia({ prefix: "/ai" })
  .use(authMiddleware)

  // ── GET /ai/status — verificar que Ollama está corriendo ──
  .get("/status", async ({ set }) => {
    try {
      const res = await fetch("http://localhost:11434/api/tags");
      if (!res.ok) throw new Error("Ollama not responding");
      const { models } = await res.json() as { models: Array<{ name: string }> };
      const modelNames = models?.map(m => m.name) ?? [];
      const asistenteListo = modelNames.some(m => m.includes("phi3"));

      return {
        success: true,
        data: {
          ollamaRunning: true,
          asistenteListo,
          availableModels: modelNames
        }
      };
    } catch {
      return {
        success: false,
        data: {
          ollamaRunning: false,
          asistenteListo: false,
          availableModels: []
        }
      };
    }
  })

  // ── POST /ai/chat — chat con streaming ────────────────────
  .post("/chat", async ({ body, set }) => {
    const { messages, companyId } = body;

    if (!companyId) {
      set.status = 400;
      return new Response(JSON.stringify({ error: "companyId required" }), {
        status: 400,
        headers: { "Content-Type": "application/json" }
      });
    }

    const context = await buildFinancialContext(companyId);
    const encoder = new TextEncoder();
    const generator = chatWithOllama(messages, companyId);

    const stream = new ReadableStream({
      async start(controller) {
        try {
          let accumulated = "";
          for await (const chunk of generator) {
            accumulated += chunk;
            controller.enqueue(encoder.encode(chunk));
          }

          const numbersInResponse = accumulated.match(/\$[\d,]+\.?\d*/g) ?? [];
          const contextString = JSON.stringify(context);
          const hallucinated = numbersInResponse.filter(n => {
            const raw = n.replace(/[$,]/g, "");
            return !contextString.includes(raw);
          });
          if (hallucinated.length > 0) {
            const warning = `\n\n⚠️ *Nota: Los siguientes valores no fueron encontrados en el contexto financiero verificado: ${hallucinated.join(", ")}. Verificá manualmente.*`;
            controller.enqueue(encoder.encode(warning));
          }
        } catch (err: unknown) {
          const errorMsg = err instanceof Error ? err.name : "UnknownError";
          const msg = errorMsg === "AbortError"
            ? "\n[Error: AI response timed out after 60 seconds]"
            : "\n[Error: AI service unavailable]";
          controller.enqueue(encoder.encode(msg));
        } finally {
          controller.close();
        }
      }
    });

    return new Response(stream, {
      headers: {
        "Content-Type": "text/plain; charset=utf-8",
        "Transfer-Encoding": "chunked",
        "Cache-Control": "no-cache",
        "X-Accel-Buffering": "no"
      }
    });
  }, {
    beforeHandle: requireAuth,
    body: t.Object({
      messages: t.Array(
        t.Object({
          role:    t.String(),
          content: t.String()
        })
      ),
      companyId: t.String()
    })
  })

  // ── GET /ai/pull-model — streaming de descarga ────────────
  .get("/pull-model", async ({ set }) => {
    const encoder = new TextEncoder();
    const stream = new ReadableStream({
      async start(controller) {
        try {
          const res = await fetch("http://localhost:11434/api/pull", {
            method: "POST",
            headers: { "Content-Type": "application/json" },
            body: JSON.stringify({ name: "phi3:mini", stream: true }),
          });

          if (!res.body) {
            controller.close();
            return;
          }

          const reader = res.body.getReader();
          const decoder = new TextDecoder();

          while (true) {
            const { done, value } = await reader.read();
            if (done) break;

            const text = decoder.decode(value, { stream: true });
            const lines = text.split("\n").filter(Boolean);

            for (const line of lines) {
              try {
                const json = JSON.parse(line);
                if (json.completed && json.total) {
                  const data = { bytesDescargados: json.completed, total: json.total, status: json.status };
                  controller.enqueue(encoder.encode(`data: ${JSON.stringify(data)}\n\n`));
                }
                if (json.status === "success") {
                  controller.enqueue(encoder.encode(`data: ${JSON.stringify({ completo: true })}\n\n`));
                }
              } catch { /* ignorar ruido */ }
            }
          }
        } catch {
          controller.enqueue(encoder.encode(`data: ${JSON.stringify({ error: true })}\n\n`));
        } finally {
          controller.close();
        }
      }
    });

    return new Response(stream, {
      headers: {
        "Content-Type": "text/event-stream",
        "Cache-Control": "no-cache",
        "Connection": "keep-alive"
      }
    });
  })

  // ── GET /ai/download-ollama — proxy de descarga ───────────
  .get("/download-ollama", async ({ query, set }) => {
    const os = query.os as string;
    const urls: Record<string, string> = {
      windows: "https://ollama.com/download/OllamaSetup.exe",
      mac:     "https://ollama.com/download/Ollama-darwin.zip",
    };

    const url = urls[os];
    if (!url) {
      set.status = 400;
      return { error: "Invalid OS" };
    }

    const response = await fetch(url, { redirect: 'follow' });
    if (!response.ok || !response.body) {
      set.status = 502;
      return { error: "Failed to fetch from ollama.com" };
    }

    return new Response(response.body, {
      headers: {
        "Content-Type":        "application/octet-stream",
        "Content-Disposition": `attachment; filename="${os === "windows" ? "OllamaSetup.exe" : "Ollama-darwin.zip"}"`,
        "Cache-Control":       "no-cache",
      },
    });
  }, {
    query: t.Object({ os: t.String() })
  });

