import { Elysia, t } from "elysia";
import { db, sql } from "../db/connection.ts";
import { users, sessions, companies, userCompanyRoles } from "../db/schema/index.ts";
import { eq, and, or, isNull } from "drizzle-orm";
import {
  verifyPassword,
  recordFailedAttempt,
  resetFailedAttempts,
  isAccountLocked,
  updateLastLogin,
  hashPassword,
  DUMMY_HASH,
} from "../services/auth.service.ts";
import {
  createSession,
  invalidateSession,
  switchSessionCompany,
  invalidateAllUserSessions,
  listActiveSessions,
} from "../services/session.service.ts";
import { createAuditEntry } from "../services/audit.service.ts";
import { loginRateLimiter } from "../middleware/rate-limit.ts";
import { authMiddleware } from "../middleware/auth.middleware.ts";

export const authRoutes = new Elysia({ prefix: "/auth" })
  .use(authMiddleware)

  // ── POST /auth/login ──────────────────────────────────────
  .post(
    "/login",
    async ({ body, cookie, request, set }) => {
      const ip = request.headers.get("x-forwarded-for") ?? "unknown";
      const ua = request.headers.get("user-agent") ?? null;

      const [user] = await db
        .select({
          id: users.id,
          username: users.username,
          passwordHash: users.passwordHash,
          isActive: users.isActive,
          isSuperAdmin: users.isSuperAdmin,
        })
        .from(users)
        .where(
          or(
            eq(users.username, body.username),
            eq(users.email, body.username)
          )
        )
        .limit(1);

      if (!user) {
        await verifyPassword(body.password, DUMMY_HASH);
        set.status = 401;
        return { error: "Invalid credentials" };
      }

      if (!user.isActive) {
        set.status = 403;
        return { error: "Account is deactivated" };
      }

      const lockStatus = await isAccountLocked(user.id);
      if (lockStatus.locked) {
        set.status = 423;
        return { error: `Account locked until ${lockStatus.until}` };
      }

      const valid = await verifyPassword(body.password, user.passwordHash);
      if (!valid) {
        await recordFailedAttempt(user.id);
        await createAuditEntry({
          companyId: null, userId: user.id, sessionId: null,
          action: "users:read", module: "users",
          entityType: "login_attempt", entityId: user.id,
          beforeState: null, afterState: { result: "failed" }, ipAddress: ip,
        });
        set.status = 401;
        return { error: "Invalid credentials" };
      }

      await resetFailedAttempts(user.id);
      await updateLastLogin(user.id, ip);

      const companyId = null;
      const sessionId = await createSession({ userId: user.id, companyId, ipAddress: ip, userAgent: ua });

      await createAuditEntry({
        companyId, userId: user.id, sessionId,
        action: "users:read", module: "users",
        entityType: "session", entityId: sessionId,
        beforeState: null, afterState: { result: "login_success" }, ipAddress: ip,
      });

      cookie["session"].set({
        value: sessionId,
        httpOnly: true,
        sameSite: "strict",
        secure: process.env["NODE_ENV"] === "production",
        path: "/",
        maxAge: 8 * 60 * 60, // 8 hours
      });

      // Fetch Full User Profile
      const [fullUser] = await db
        .select({
          id: users.id,
          username: users.username,
          email: users.email,
          firstName: users.firstName,
          lastName: users.lastName,
          isSuperAdmin: users.isSuperAdmin
        })
        .from(users)
        .where(eq(users.id, user.id))
        .limit(1);

      // Fetch Available Companies
      let comps = [];
      if (user.isSuperAdmin) {
        comps = await db
          .select({ id: companies.id, legalName: companies.legalName })
          .from(companies)
          .where(eq(companies.isActive, true));
      } else {
        comps = await db
          .select({ id: companies.id, legalName: companies.legalName })
          .from(companies)
          .innerJoin(userCompanyRoles, eq(companies.id, userCompanyRoles.companyId))
          .where(
            and(
              eq(userCompanyRoles.userId, user.id),
              eq(companies.isActive, true),
              eq(userCompanyRoles.isActive, true),
              isNull(userCompanyRoles.revokedAt)
            )
          );
      }

      return { 
        message: "Login successful", 
        sessionId,
        user: fullUser,
        companies: comps 
      };
    },
    {
      beforeHandle: loginRateLimiter(5, 15 * 60 * 1000), // 5 attempts per 15 mins
      body: t.Object({
        username:  t.String({ minLength: 1 }),
        password:  t.String({ minLength: 1 }),
      }),
    }
  )

  // ── POST /auth/select-company ─────────────────────────────
  .post(
    "/select-company",
    async ({ body, user, sessionId, request, set }) => {
      if (!user) { set.status = 401; return { error: "Not authenticated" }; }

      const [session] = await db
        .select({ companyId: sessions.companyId })
        .from(sessions)
        .where(eq(sessions.id, sessionId))
        .limit(1);

      if (!session) { set.status = 401; return { error: "Invalid session" }; }
      if (session.companyId) { set.status = 400; return { error: "Company already selected. Use /switch-company instead." }; }

      const [role] = await db
        .select({ id: userCompanyRoles.id })
        .from(userCompanyRoles)
        .where(
          and(
            eq(userCompanyRoles.userId, user),
            eq(userCompanyRoles.companyId, body.companyId),
            eq(userCompanyRoles.isActive, true),
            isNull(userCompanyRoles.revokedAt)
          )
        )
        .limit(1);

      if (!role) {
        const [dbUser] = await db.select({ isSuperAdmin: users.isSuperAdmin }).from(users).where(eq(users.id, user)).limit(1);
        if (!dbUser || !dbUser.isSuperAdmin) {
          set.status = 403; return { error: "Access denied to this company" };
        }
      }

      await switchSessionCompany(sessionId, body.companyId);

      const ip = request.headers.get("x-forwarded-for") ?? "unknown";
      await createAuditEntry({
        companyId: body.companyId, userId: user, sessionId,
        action: "session:select_company", module: "auth",
        entityType: "session", entityId: sessionId,
        beforeState: null, afterState: { result: "company_selected", companyId: body.companyId }, ipAddress: ip,
      });

      return { message: "Company selected successfully" };
    },
    { body: t.Object({ companyId: t.String() }) }
  )

  // ── POST /auth/switch-company ─────────────────────────────
  .post(
    "/switch-company",
    async ({ body, user, sessionId, request, set }) => {
      if (!user) { set.status = 401; return { error: "Not authenticated" }; }

      const [role] = await db
        .select({ id: userCompanyRoles.id })
        .from(userCompanyRoles)
        .where(
          and(
            eq(userCompanyRoles.userId, user),
            eq(userCompanyRoles.companyId, body.companyId),
            eq(userCompanyRoles.isActive, true),
            isNull(userCompanyRoles.revokedAt)
          )
        )
        .limit(1);

      if (!role) {
        const [dbUser] = await db.select({ isSuperAdmin: users.isSuperAdmin }).from(users).where(eq(users.id, user)).limit(1);
        if (!dbUser || !dbUser.isSuperAdmin) {
          set.status = 403; return { error: "Access denied to this company" };
        }
      }

      await switchSessionCompany(sessionId, body.companyId);

      const ip = request.headers.get("x-forwarded-for") ?? "unknown";
      await createAuditEntry({
        companyId: body.companyId, userId: user, sessionId,
        action: "session:switch_company", module: "auth",
        entityType: "session", entityId: sessionId,
        beforeState: null, afterState: { result: "company_switched", companyId: body.companyId }, ipAddress: ip,
      });

      return { message: "Company switched successfully" };
    },
    { body: t.Object({ companyId: t.String() }) }
  )

  // ── POST /auth/logout ─────────────────────────────────────
  .post("/logout", async ({ cookie }) => {
    const token = (cookie["session"].value as string);
    if (token) {
      await invalidateSession(token);
      cookie["session"].remove();
    }
    return { message: "Logged out" };
  })

  // ── POST /auth/logout-all — revoke all sessions ───────────
  .post("/logout-all", async ({ user, sessionId, set, cookie }) => {
    if (!user) { set.status = 401; return { error: "Not authenticated" }; }
    const count = await invalidateAllUserSessions(user);
    cookie["session"].remove();
    return { success: true, message: `${count} session(s) revoked.` };
  })

  // ── GET /auth/sessions — list active sessions ─────────────
  .get("/sessions", async ({ user, sessionId, set }) => {
    if (!user) { set.status = 401; return { error: "Not authenticated" }; }
    const activeSessions = await listActiveSessions(user);
    return { success: true, data: activeSessions };
  })

  // ── POST /auth/change-password ────────────────────────────
  .post(
    "/change-password",
    async ({ body, user, set }) => {
      if (!user) { set.status = 401; return { error: "Not authenticated" }; }

      const [dbUser] = await db
        .select({ passwordHash: users.passwordHash })
        .from(users)
        .where(eq(users.id, user))
        .limit(1);

      if (!dbUser) { set.status = 404; return { error: "User not found" }; }

      const valid = await verifyPassword(body.currentPassword, dbUser.passwordHash);
      if (!valid) { set.status = 401; return { error: "Current password is incorrect" }; }

      const { hash: newHash, salt: newSalt } = await hashPassword(body.newPassword);

      await db.update(users)
        .set({
          passwordHash: newHash,
          passwordSalt: newSalt,
          mustChangePassword: false,
          updatedAt: new Date(),
        })
        .where(eq(users.id, user));

      return { message: "Password changed successfully" };
    },
    {
      body: t.Object({
        currentPassword: t.String({ minLength: 1 }),
        newPassword:     t.String({ minLength: 8 }),
      }),
    }
  );

import { Elysia, t } from 'elysia';
import { db } from '../db/connection';
import { bankAccounts } from '../db/schema';
import { eq, and } from 'drizzle-orm';
import { v4 as uuidv4 } from 'uuid';
import { requireAuth } from "../middleware/auth.middleware.ts";

export const bankAccountsRoutes = new Elysia({ prefix: '/bank-accounts' })
  .guard({ beforeHandle: requireAuth })
  .get('/', async ({ query }) => {
    const { companyId } = query as { companyId?: string };
    if (!companyId) return [];

    const accounts = await db.query.bankAccounts.findMany({
      where: and(
        eq(bankAccounts.companyId, companyId),
        eq(bankAccounts.isActive, true)
      ),
      orderBy: (bankAccounts, { asc }) => [asc(bankAccounts.accountName)]
    });
    return accounts.map(a => ({
      ...a,
      balance: (a.balance || 0) / 100
    }));
  }, {
    query: t.Object({ companyId: t.String() })
  })

  .post('/', async ({ body, set }) => {
    const data = body as any;
    try {
      if (data.companyId && data.accountNumber) {
        const existing = await db.query.bankAccounts.findFirst({
          where: and(
            eq(bankAccounts.companyId, data.companyId),
            eq(bankAccounts.accountNumber, data.accountNumber)
          )
        });
        if (existing) return existing;
      }

      const now = new Date();
      const newAccount = {
        id: uuidv4(),
        companyId: data.companyId,
        accountName: data.accountName,
        bankName: data.bankName,
        accountNumber: data.accountNumber || null,
        accountType: data.accountType || 'checking',
        balance: Math.round((data.balance || 0) * 100),
        glAccountId: data.glAccountId || null,
        isActive: true,
        createdAt: now,
        updatedAt: now
      };

      await db.insert(bankAccounts).values(newAccount);
      return newAccount;
    } catch (error: any) {
      set.status = 500;
      return { error: 'Failed to create bank account', details: error.message };
    }
  }, {
    body: t.Object({
      companyId: t.String(),
      accountName: t.String(),
      bankName: t.String(),
      accountNumber: t.Optional(t.String()),
      accountType: t.Optional(t.String()),
      balance: t.Optional(t.Number()),
      currency: t.Optional(t.String()),
      routingNumber: t.Optional(t.String()),
      notes: t.Optional(t.String()),
      glAccountId: t.Optional(t.String())
    })
  })

  .put('/:id', async ({ params, body, set }) => {
    const { id } = params;
    const data = body as any;
    try {
      const now = new Date();

      const updateData: any = {
        updatedAt: now
      };

      if (data.accountName !== undefined) updateData.accountName = data.accountName;
      if (data.bankName !== undefined) updateData.bankName = data.bankName;
      if (data.accountNumber !== undefined) updateData.accountNumber = data.accountNumber;
      if (data.accountType !== undefined) updateData.accountType = data.accountType;
      if (data.balance !== undefined) updateData.balance = Math.round(data.balance * 100);
      if (data.glAccountId !== undefined) updateData.glAccountId = data.glAccountId;
      if (data.isActive !== undefined) updateData.isActive = data.isActive ? true : false;

      const updated = await db.update(bankAccounts)
        .set(updateData)
        .where(eq(bankAccounts.id, id))
        .returning();

      if (updated.length === 0) {
        set.status = 404;
        return { error: 'Bank account not found' };
      }

      return updated[0];
    } catch (error: any) {
      set.status = 500;
      return { error: 'Failed to update bank account', details: error.message };
    }
  }, {
    body: t.Object({
      accountName: t.Optional(t.String()),
      bankName: t.Optional(t.String()),
      accountNumber: t.Optional(t.String()),
      accountType: t.Optional(t.String()),
      glAccountId: t.Optional(t.String()),
      isActive: t.Optional(t.Boolean())
    })
  })

  .delete('/:id', async ({ params, set }) => {
    const { id } = params;
    try {
      const now = new Date();
      const updated = await db.update(bankAccounts)
        .set({ isActive: false, updatedAt: now })
        .where(eq(bankAccounts.id, id))
        .returning();

      if (updated.length === 0) {
        set.status = 404;
        return { error: 'Bank account not found' };
      }

      return { success: true, message: 'Bank account deactivated successfully' };
    } catch (error: any) {
      set.status = 500;
      return { error: 'Failed to deactivate bank account', details: error.message };
    }
  });

// ============================================================
// BANK ROUTES — PostgreSQL 16 / Drizzle ORM
// ============================================================

import { Elysia, t } from "elysia";
import { statementImportService } from "../services/bank/statement-import.service.ts";
import { suggestAccountBatch } from "../services/bank/smart-match.service.ts";
import { matchTransaction, ignoreTransaction } from "../services/bank/reconciliation.service.ts";
import { requirePermission } from "../middleware/rbac.middleware.ts";
import { requireAuth, authMiddleware } from "../middleware/auth.middleware.ts";

import { db, sql } from "../db/connection.ts";
import { eq, and } from "drizzle-orm";
import { bankTransactions } from "../db/schema/index.ts";

export const bankRoutes = new Elysia({ prefix: "/bank" })
  .use(authMiddleware)
  .guard({ beforeHandle: requireAuth })
  // ─────────────────────────────────────────────────────────────
  // 1. IMPORT CSV (bank:create)
  // ─────────────────────────────────────────────────────────────
  .use(requirePermission("bank", "create"))
  .post(
    "/import",
    async ({ body, set }) => {
      const file = body.file as File;
      const arrayBuffer = await file.arrayBuffer();
      const buffer = Buffer.from(arrayBuffer);

      if (file.name.toLowerCase().endsWith('.pdf')) {
        set.status = 400;
        return { error: 'PDF_REQUIRES_CLIENT_PARSE', message: 'Los PDFs se procesan en el navegador antes de enviarse.' };
      }

      try {
        const result = await statementImportService.processFile(
          body.companyId,
          body.bankAccountId || "",
          buffer,
          file.name
        );
        return { success: true, ...result };
      } catch (err: any) {
        try {
          const parsed = JSON.parse(err.message);
          if (parsed.code === 'UNKNOWN_BANK') {
            set.status = 400;
            return { error: 'UNKNOWN_BANK', bankName: parsed.bankName };
          }
        } catch(e) {}
        set.status = 500;
        return { error: err.message };
      }
    },
    {
      body: t.Object({
        file: t.File(),
        bankAccountId: t.Optional(t.String()),
        companyId: t.String()
      })
    }
  )

  // ─────────────────────────────────────────────────────────────
  // 1B. IMPORT JSON PARSED TRANSACTIONS (bank:create)
  // ─────────────────────────────────────────────────────────────
  .post(
    "/import-parsed",
    async ({ body, set }) => {
      try {
        const result = await statementImportService.processParsedBatch(
          body.companyId,
          body.bankAccountId || undefined,
          body.transactions,
          body.bankName || undefined,
          body.accountNumber || undefined,
          body.importBatchId
        );
        return { success: true, ...result };
      } catch (err: any) {
        try {
          const parsed = JSON.parse(err.message);
          if (parsed.code === 'UNKNOWN_BANK') {
            set.status = 400;
            return { error: 'UNKNOWN_BANK', bankName: parsed.bankName, accountNumber: parsed.accountNumber };
          }
        } catch(e) {}
        set.status = 500;
        return { error: err.message };
      }
    },
    {
      body: t.Object({
        transactions: t.Array(t.Object({
          date: t.String(),
          description: t.String(),
          amount: t.Number(),
          balance: t.Optional(t.Number())
        })),
        bankAccountId: t.Optional(t.String()),
        bankName: t.Optional(t.String()),
        accountNumber: t.Optional(t.String()),
        fileName: t.String(),
        importBatchId: t.String(),
        companyId: t.String()
      })
    }
  )

  // ─────────────────────────────────────────────────────────────
  // 2. GET TRANSACTIONS (bank:read)
  // ─────────────────────────────────────────────────────────────
  .use(requirePermission("bank", "read"))
  .get(
    "/transactions",
    async ({ query }) => {
      let condition = eq(bankTransactions.companyId, query.companyId);
      if (query.status) {
        condition = and(condition, eq(bankTransactions.status, query.status)) as any;
      }

      const txs = await db
        .select()
        .from(bankTransactions)
        .where(condition)
        .orderBy(sql`${bankTransactions.transactionDate} DESC`);

      const descriptions = txs.map(tx => tx.description);
      const suggestionMap = await suggestAccountBatch(query.companyId, descriptions);
      const enriched = txs.map(tx => {
        const suggestions = suggestionMap.get(tx.description) ?? [];
        return {
          ...tx,
          suggestedCategory: suggestions[0]?.accountId ?? null,
          confidenceScore: suggestions[0]?.confidence ?? 0,
          isDuplicate: false,
        };
      });

      return { success: true, data: enriched };
    },
    {
      query: t.Object({
        companyId: t.String(),
        status: t.Optional(t.String())
      })
    }
  )

  // ─────────────────────────────────────────────────────────────
  // 3. GET MATCH SUGGESTIONS (bank:read)
  // ─────────────────────────────────────────────────────────────
  .use(requirePermission("bank", "read"))
  .get(
    "/suggest",
    async ({ query }) => {
      const suggestionMap = await suggestAccountBatch(query.companyId, [query.description]);
      return { success: true, data: suggestionMap.get(query.description) ?? [] };
    },
    {
      query: t.Object({
        companyId: t.String(),
        description: t.String()
      })
    }
  )

  // ─────────────────────────────────────────────────────────────
  // 4. RECONCILE (bank:reconcile)
  // ─────────────────────────────────────────────────────────────
  .use(requirePermission("bank", "approve"))
  .post(
    "/reconcile/:id",
    async ({ params, body, request, set, user, sessionId }) => {
      const uid = user!;
      const sid = sessionId!;
      const ip = request.headers.get("x-forwarded-for") ?? "unknown";

      const draftId = await matchTransaction(
        body.companyId,
        params.id,
        body.targetAccountId,
        body.bankAccountId,
        body.periodId,
        uid,
        sid,
        ip
      );

      return { success: true, journalEntryId: draftId };
    },
    {
      params: t.Object({
        id: t.String()
      }),
      body: t.Object({
        companyId: t.String(),
        targetAccountId: t.String(),
        bankAccountId: t.String(),
        periodId: t.String()
      })
    }
  )

  // ─────────────────────────────────────────────────────────────
  // 5. IGNORE & 6. ASSIGN
  // ─────────────────────────────────────────────────────────────
  .group("", app => app
    .use(requirePermission("bank", "approve"))
    .post(
    "/ignore/:id",
    async ({ params, body, request, set, user }) => {
      const uid = user!;
      const ip = request.headers.get("x-forwarded-for") ?? "unknown";

      await ignoreTransaction(body.companyId, params.id, uid, ip);
      return { success: true };
    },
    {
      params: t.Object({ id: t.String() }),
      body: t.Object({ companyId: t.String() })
    }
  )

  // ─────────────────────────────────────────────────────────────
  // 6. ASSIGN GL ACCOUNT
  // ─────────────────────────────────────────────────────────────
  .patch(
    "/transactions/:id/assign",
    async ({ params, body, set }) => {
      if (!body.companyId || !body.glAccountId) {
        set.status = 400;
        return { error: "companyId y glAccountId requeridos" };
      }

      const [existing] = await db
        .select({ id: bankTransactions.id })
        .from(bankTransactions)
        .where(
          and(
            eq(bankTransactions.id, params.id),
            eq(bankTransactions.companyId, body.companyId)
          )
        )
        .limit(1);

      if (!existing) { set.status = 404; return { error: "Transacción no encontrada" }; }

      await db.update(bankTransactions)
        .set({ glAccountId: body.glAccountId, status: "assigned" })
        .where(eq(bankTransactions.id, params.id));

      return { success: true, message: "Cuenta asignada" };
    },
    {
      params: t.Object({ id: t.String() }),
      body: t.Object({
        companyId: t.String(),
        glAccountId: t.String()
      })
    }
  ));

