import { Elysia, t } from "elysia";

import { db, sql } from "../db/connection.ts";
import { bankAccounts, bankTransactions, fiscalPeriods, journalLines, journalEntries, chartOfAccounts } from "../db/schema/index.ts";
import { eq, and, lte } from "drizzle-orm";
import { requirePermission } from "../middleware/rbac.middleware.ts";
import { verifyAuditChain } from "../services/audit.service.ts";
import { getBalanceSheet } from "../services/reports/balance-sheet.service.ts";
import { requireAuth } from "../middleware/auth.middleware.ts";

export const dashboardRoutes = new Elysia({ prefix: "/dashboard" })
  .guard({ beforeHandle: requireAuth })
  .use(requirePermission("reports", "read"))
  .get("/", async ({ query, set }) => {
    const companyId = query.companyId;

    try {
      // Get bank balance
      const [bankResult] = await db
        .select({ total: sql`SUM(${bankAccounts.balance})`.mapWith(Number) })
        .from(bankAccounts)
        .where(eq(bankAccounts.companyId, companyId))
        .limit(1);

      // Get pending transactions
      const [pendingResult] = await db
        .select({ count: sql`COUNT(*)`.mapWith(Number) })
        .from(bankTransactions)
        .where(
          and(
            eq(bankTransactions.companyId, companyId),
            eq(bankTransactions.status, "pending")
          )
        )
        .limit(1);

      // Ensure chain integrity
      const chainValidObj = await verifyAuditChain();
      const chainValid = chainValidObj.valid;

      // Active Period
      const [periodResult] = await db
        .select({ name: fiscalPeriods.name, endDate: fiscalPeriods.endDate })
        .from(fiscalPeriods)
        .where(
          and(
            eq(fiscalPeriods.companyId, companyId),
            eq(fiscalPeriods.status, "open")
          )
        )
        .orderBy(sql`${fiscalPeriods.startDate} ASC`)
        .limit(1);

      const today = new Date().toISOString().split('T')[0];
      const bs = await getBalanceSheet(companyId, today);

      // Raw query for revenue/expense summary using Drizzle tagged template
      const [revExp] = await db
        .select({
          revenue: sql`SUM(CASE WHEN ${chartOfAccounts.accountType} = 'revenue' THEN (${journalLines.creditAmount} - ${journalLines.debitAmount}) ELSE 0 END)`.mapWith(Number),
          expenses: sql`SUM(CASE WHEN ${chartOfAccounts.accountType} = 'expense' THEN (${journalLines.debitAmount} - ${journalLines.creditAmount}) ELSE 0 END)`.mapWith(Number)
        })
        .from(journalLines)
        .innerJoin(journalEntries, eq(journalLines.journalEntryId, journalEntries.id))
        .innerJoin(chartOfAccounts, eq(journalLines.accountId, chartOfAccounts.id))
        .where(
          and(
            eq(journalEntries.companyId, companyId),
            eq(journalEntries.status, "posted"),
            lte(journalEntries.entryDate, sql`${today}::date`)
          )
        )
        .limit(1);

      const inc = revExp?.revenue || 0;
      const exp = revExp?.expenses || 0;

      return {
        success: true,
        data: {
          bankBalance: bankResult?.total || 0,
          pendingCount: pendingResult?.count || 0,
          totalAssets: bs.assets.total,
          totalLiabilities: bs.liabilities.total,
          netIncome: inc - exp,
          income: inc,
          expenses: exp,
          activePeriod: {
            name: periodResult?.name || "No open period",
            endDate: periodResult?.endDate || "N/A"
          },
          chainValid: chainValid
        }
      };
    } catch (err: any) {
      set.status = 400;
      return { error: err.message };
    }
  }, {
    query: t.Object({
      companyId: t.String()
    })
  });

import { Elysia, t } from 'elysia';
import { db } from '../db/connection';
import { chartOfAccounts } from '../db/schema';
import { eq, and } from 'drizzle-orm';
import { US_GAAP_ACCOUNTS } from '../db/seeds/gl-accounts.seed';
import { v4 as uuidv4 } from 'uuid';

export const glAccountsRoutes = new Elysia({ prefix: '/gl-accounts' })

  // GET /gl-accounts?companyId=xxx
  .get('/', async ({ query }) => {
    const { companyId } = query as { companyId?: string };
    if (!companyId) return [];
    const existing = await db.select().from(chartOfAccounts)
      .where(eq(chartOfAccounts.companyId, companyId)).limit(1);
    if (existing.length === 0) {
      const now = new Date();
      for (const acc of US_GAAP_ACCOUNTS) {
        await db.insert(chartOfAccounts).values({
          id: uuidv4(), companyId, code: acc.code, name: acc.name,
          accountType: acc.type, description: acc.subtype,
          normalBalance: acc.normalBalance, isSystem: acc.isSystem ? true : false,
          isActive: true, createdAt: now, updatedAt: now,
        }).onConflictDoNothing();
      }
    }
    const accounts = await db.select().from(chartOfAccounts)
      .where(eq(chartOfAccounts.companyId, companyId));
    return accounts.filter(a => a.isActive).sort((a, b) => a.code.localeCompare(b.code));
  }, { query: t.Object({ companyId: t.String() }) })

  // POST /gl-accounts — crear cuenta nueva
  .post('/', async ({ body, set }) => {
    const { companyId, code, name, accountType, normalBalance, description, parentCode } = body as any;
    if (!companyId || !code || !name || !accountType || !normalBalance) {
      set.status = 400; return { error: 'Faltan campos requeridos' };
    }
    const existing = await db.select().from(chartOfAccounts)
      .where(and(eq(chartOfAccounts.companyId, companyId), eq(chartOfAccounts.code, code))).limit(1);
    if (existing.length > 0) { set.status = 409; return { error: `El código ${code} ya existe` }; }
    const now = new Date();
    const id = uuidv4();
    await db.insert(chartOfAccounts).values({
      id, companyId, code, name, accountType, normalBalance,
      description: description || null, isSystem: false, isActive: true,
      createdAt: now, updatedAt: now,
    });
    return { id, message: 'Cuenta creada' };
  })

  // PATCH /gl-accounts/:id — editar nombre/descripción/código
  .patch('/:id', async ({ params, body, set }) => {
    const { id } = params;
    const { companyId, name, description, code } = body as any;
    if (!companyId) { set.status = 400; return { error: 'companyId requerido' }; }
    const account = await db.select().from(chartOfAccounts)
      .where(and(eq(chartOfAccounts.id, id), eq(chartOfAccounts.companyId, companyId))).limit(1);
    if (account.length === 0) { set.status = 404; return { error: 'Cuenta no encontrada' }; }
    const updates: any = { updatedAt: new Date() };
    if (name) updates.name = name;
    if (description !== undefined) updates.description = description;
    if (code) {
      const codeExists = await db.select().from(chartOfAccounts)
        .where(and(eq(chartOfAccounts.companyId, companyId), eq(chartOfAccounts.code, code))).limit(1);
      if (codeExists.length > 0 && codeExists[0].id !== id) {
        set.status = 409; return { error: `El código ${code} ya está en uso` };
      }
      updates.code = code;
    }
    await db.update(chartOfAccounts).set(updates).where(eq(chartOfAccounts.id, id));
    return { message: 'Cuenta actualizada' };
  })

  // DELETE /gl-accounts/:id?companyId=xxx
  .delete('/:id', async ({ params, query, set }) => {
    const { id } = params;
    const { companyId } = query as { companyId?: string };
    if (!companyId) { set.status = 400; return { error: 'companyId requerido' }; }
    const account = await db.select().from(chartOfAccounts)
      .where(and(eq(chartOfAccounts.id, id), eq(chartOfAccounts.companyId, companyId))).limit(1);
    if (account.length === 0) { set.status = 404; return { error: 'Cuenta no encontrada' }; }
    // Desactivar (soft delete) — la restricción de movimientos se agrega cuando exista la tabla de asientos
    await db.update(chartOfAccounts)
      .set({ isActive: false, updatedAt: new Date() })
      .where(eq(chartOfAccounts.id, id));
    return { message: 'Cuenta desactivada' };
  }, { query: t.Object({ companyId: t.String() }) });

