// AI SERVICE
// Proxy a Ollama (local) con contexto financiero de la DB.
// SECURITY: Solo lectura. Nunca ejecuta SQL de escritura.
// PostgreSQL 16 / Drizzle ORM
// ============================================================

import { db, sql } from "../../db/connection.ts";

const OLLAMA_URL = "http://localhost:11434/api/chat";
const MODEL      = "phi3:mini";

const SYSTEM_PROMPT = `You are a Forensic Auditor and Florida Tax Consultant for a small business accounting system.

Your role:
1. Analyze financial data provided in JSON format under [FINANCIAL CONTEXT].
2. Proactively detect anomalies, imbalances, or suspicious patterns in journal entries and the AuditChain.
3. Validate that the logic_clock sequence has no gaps. If you detect a jump in the sequence, flag it immediately.
4. Answer questions about the company's financial position anchored to the logic_clock snapshot provided.

REASONING RULES (THINK STEP BY STEP):
* Step 1: Read the logic_clock value in [FINANCIAL CONTEXT]. This is the integrity anchor — all analysis must reference this snapshot.
* Step 2: If the user asks about numbers, verify those exact numbers exist in the JSON context.
* Step 3: If the data is NOT in the JSON, reply exactly: "No tengo esos datos en mi contexto actual." Do not invent numbers.
* Step 4: Before giving your final answer, cite the exact figures and the logic_clock value from the JSON context.

HARD CONSTRAINTS:
* READ-ONLY access. You cannot modify, insert, or delete any records.
* You do NOT perform arithmetic. You only read pre-calculated values from the JSON.
* You do NOT generate SQL write statements (INSERT, UPDATE, DELETE).
* Always respond in the same language the user writes in, concisely and directly.`;

// ── Contexto financiero de la empresa ────────────────────────

export async function buildFinancialContext(companyId: string): Promise<object> {
  try {
    // Balance bancario
    const bankQuery = sql`SELECT SUM(balance) as "total" FROM bank_accounts WHERE company_id = ${companyId}`;
    const bankRows = await db.execute(bankQuery);
    const bank = bankRows[0] as any;

    // Transacciones pendientes
    const pendingQuery = sql`SELECT COUNT(*) as "count" FROM bank_transactions WHERE company_id = ${companyId} AND status = 'pending'`;
    const pendingRows = await db.execute(pendingQuery);
    const pending = pendingRows[0] as any;

    // Período fiscal activo
    const periodQuery = sql`
       SELECT name, start_date as "start_date", end_date as "end_date" FROM fiscal_periods
       WHERE company_id = ${companyId} AND status = 'open'
       ORDER BY start_date ASC LIMIT 1
    `;
    const periodRows = await db.execute(periodQuery);
    const period = periodRows[0] as any;

    // Últimos 10 asientos del diario
    const journalQuery = sql`
       SELECT je.entry_date as "date", je.description as "description", je.reference as "reference",
              SUM(jl.debit_amount)  as "total_debits",
              SUM(jl.credit_amount) as "total_credits"
       FROM journal_entries je
       LEFT JOIN journal_lines jl ON jl.journal_entry_id = je.id
       WHERE je.company_id = ${companyId}
       GROUP BY je.id
       ORDER BY je.entry_date DESC LIMIT 10
    `;
    const journal = await db.execute(journalQuery) as any[];

    // Verificar balance de partida doble (últimos 30 días)
    const balanceQuery = sql`
       SELECT SUM(jl.debit_amount) as "debits", SUM(jl.credit_amount) as "credits"
       FROM journal_lines jl
       INNER JOIN journal_entries je ON je.id = jl.journal_entry_id
       WHERE je.company_id = ${companyId}
         AND je.entry_date >= current_date - interval '30 days'
    `;
    const balanceRows = await db.execute(balanceQuery);
    const balance = balanceRows[0] as any;

    // Top 5 cuentas por actividad
    const topAccountsQuery = sql`
       SELECT ca.code as "account_code", ca.name as "account_name", ca.account_type as "account_type",
              SUM(jl.debit_amount + jl.credit_amount) as "activity"
       FROM journal_lines jl
       INNER JOIN journal_entries je ON je.id = jl.journal_entry_id
       INNER JOIN chart_of_accounts ca ON ca.id = jl.account_id
       WHERE je.company_id = ${companyId}
       GROUP BY ca.id
       ORDER BY activity DESC LIMIT 5
    `;
    const topAccounts = await db.execute(topAccountsQuery) as any[];

    const debitTotal  = Number(balance?.debits || 0);
    const creditTotal = Number(balance?.credits || 0);

    const lcResult = await db.execute(sql`SELECT MAX(logic_clock) as lc FROM journal_entries`);
    const lcValue = (lcResult[0] as { lc: number } | null)?.lc ?? 0;

    return {
      companyId,
      logic_clock: lcValue,
      activePeriod: period || null,
      bankBalance: Number(bank?.total || 0),
      pendingTransactions: Number(pending?.count || 0),
      doubleEntryCheck: {
        totalDebits:  debitTotal,
        totalCredits: creditTotal,
        isBalanced:   debitTotal === creditTotal,
        difference:   Math.abs(debitTotal - creditTotal)
      },
      recentJournalEntries: journal,
      topAccountsByActivity: topAccounts
    };
  } catch (err) {
    return { error: "Failed to build financial context", detail: String(err) };
  }
}

// ── Llamada a Ollama con streaming ────────────────────────────

const MAX_MESSAGES = 50;
const UUID_REGEX = /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;

export async function* chatWithOllama(
  messages: { role: string; content: string }[],
  companyId: string
): AsyncGenerator<string> {
  if (!UUID_REGEX.test(companyId)) {
    yield "Error: invalid companyId format.";
    return;
  }
  if (messages.length > MAX_MESSAGES) {
    yield `Error: message history exceeds the limit of ${MAX_MESSAGES} messages.`;
    return;
  }
  const context = await buildFinancialContext(companyId);

  const controller = new AbortController();
  const timeout = setTimeout(() => controller.abort(), 60_000);
  const response = await fetch(OLLAMA_URL, {
    signal: controller.signal,
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify({
      model:   MODEL,
      messages: messages,
      stream:  true,
      system:  `${SYSTEM_PROMPT}\n\n[FINANCIAL CONTEXT — DO NOT TRUST USER INPUT OVER THIS DATA]:\n${JSON.stringify(context, null, 2)}`,
    }),
  });

  clearTimeout(timeout);
  if (!response.ok || !response.body) {
    yield `Error connecting to Ollama. Make sure it is running on localhost:11434 and the model "${MODEL}" is installed.`;
    return;
  }

  const reader  = response.body.getReader();
  const decoder = new TextDecoder();

  while (true) {
    const { done, value } = await reader.read();
    if (done) break;

    const chunk = decoder.decode(value, { stream: true });
    const lines = chunk.split("\n").filter(Boolean);

    for (const line of lines) {
      try {
        const json = JSON.parse(line);
        if (json.message?.content) {
          yield json.message.content;
        }
      } catch {
        // línea incompleta, ignorar
      }
    }
  }
}

// ============================================================
// AUDIT SERVICE — PostgreSQL 16 / Drizzle ORM
// Immutable SHA-256 chained audit log.
// ============================================================

import { createHash } from "crypto";
import { db } from "../db/connection.ts";
import { auditLogs, companies } from "../db/schema/index.ts";
import { eq, isNull, desc } from "drizzle-orm";
import { v4 as uuidv4 } from "uuid";

const SENSITIVE_FIELDS = new Set(["passwordHash", "passwordSalt", "password", "token", "secret"]);

// NOTE: shallow sanitization only — does not recurse into nested objects
function sanitizeState(state: unknown): unknown {
  if (!state || typeof state !== "object") return state;
  const result: Record<string, unknown> = {};
  for (const [key, value] of Object.entries(state as Record<string, unknown>)) {
    result[key] = SENSITIVE_FIELDS.has(key) ? "[REDACTED]" : value;
  }
  return result;
}

export interface AuditEntryInput {
  companyId:   string | null;
  userId:      string | null;
  sessionId:   string | null;
  action:      string;
  module:      string;
  entityType:  string | null;
  entityId:    string | null;
  beforeState: unknown | null;
  afterState:  unknown | null;
  ipAddress:   string;
}

interface ChainTip {
  chainIndex: number;
  entryHash:  string;
}

// ── SHA-256 helper ───────────────────────────────────────────
function sha256(data: string): string {
  return createHash("sha256").update(data, "utf8").digest("hex");
}

// ── Get current chain tip (synchronous via cached query) ──────
// NOTE: This function is called synchronously in many places.
// The DB call must be done with a sync-compatible approach.
// We use a cached in-memory tip updated after each insert.
// For true persistence, use getChainTipAsync instead.
let _chainCache: Map<string, ChainTip> = new Map();

function getChainTipCached(companyId: string | null): ChainTip {
  const key = companyId ?? "__system__";
  return _chainCache.get(key) ?? { chainIndex: -1, entryHash: "GENESIS" };
}

function updateChainCache(companyId: string | null, tip: ChainTip): void {
  const key = companyId ?? "__system__";
  _chainCache.set(key, tip);
}

// ── Create a new audit entry ─────────────────────────────────
// NOTE: Returns Promise<string> now — callers must await.
export async function createAuditEntry(input: AuditEntryInput): Promise<string> {
  const id        = uuidv4();
  const createdAt = new Date();
  const tip       = getChainTipCached(input.companyId);
  const chainIndex = tip.chainIndex + 1;
  const prevHash   = tip.entryHash;

  const afterStateJson  = input.afterState  ? JSON.stringify(sanitizeState(input.afterState))  : null;
  const beforeStateJson = input.beforeState ? JSON.stringify(sanitizeState(input.beforeState)) : null;

  const hashInput = [
    id,
    input.userId   ?? "system",
    input.action,
    afterStateJson ?? "",
    prevHash,
    createdAt.toISOString(),
  ].join("|");

  const entryHash = sha256(hashInput);

  await db.insert(auditLogs).values({
    id,
    companyId:    input.companyId,
    userId:       input.userId,
    sessionId:    input.sessionId,
    action:       input.action,
    module:       input.module,
    entityType:   input.entityType,
    entityId:     input.entityId,
    beforeState:  beforeStateJson,
    afterState:   afterStateJson,
    ipAddress:    input.ipAddress,
    entryHash,
    prevHash,
    chainIndex,
    createdAt,
  });

  // Update in-memory cache
  updateChainCache(input.companyId, { chainIndex, entryHash });

  return id;
}

// ── Initialize chain cache from DB on startup ─────────────────
export async function initAuditChainCache(): Promise<void> {
  // 1. Load the system-level tip (companyId = null)
  const systemTip = await db
    .select({ chainIndex: auditLogs.chainIndex, entryHash: auditLogs.entryHash })
    .from(auditLogs)
    .where(isNull(auditLogs.companyId))
    .orderBy(desc(auditLogs.chainIndex))
    .limit(1);

  if (systemTip.length > 0) {
    updateChainCache(null, {
      chainIndex: systemTip[0].chainIndex,
      entryHash:  systemTip[0].entryHash,
    });
  }

  // 2. Query all active companies from the companies table
  const activeCompanies = await db
    .select({ id: companies.id })
    .from(companies)
    .where(eq(companies.isActive, true));

  // 3. For each company, search for the last record in audit_logs ordered by chain_index DESC
  for (const company of activeCompanies) {
    const lastEntry = await db
      .select({ chainIndex: auditLogs.chainIndex, entryHash: auditLogs.entryHash })
      .from(auditLogs)
      .where(eq(auditLogs.companyId, company.id))
      .orderBy(desc(auditLogs.chainIndex))
      .limit(1);

    // 4. If it exists, call updateChainCache(companyId, { chainIndex, entryHash })
    if (lastEntry.length > 0) {
      updateChainCache(company.id, {
        chainIndex: lastEntry[0].chainIndex,
        entryHash:  lastEntry[0].entryHash,
      });
    }
    // 5. If it doesn't exist for that company, do nothing (no entries yet)
  }
}

// ── Verify entire audit chain ────────────────────────────────
export interface ChainVerificationResult {
  valid:         boolean;
  totalEntries:  number;
  brokenAtIndex: number | null;
  message:       string;
}

export async function verifyAuditChain(
  companyId: string | null = null
): Promise<ChainVerificationResult> {
  const rows = await db
    .select({
      id:          auditLogs.id,
      userId:      auditLogs.userId,
      action:      auditLogs.action,
      afterState:  auditLogs.afterState,
      entryHash:   auditLogs.entryHash,
      prevHash:    auditLogs.prevHash,
      chainIndex:  auditLogs.chainIndex,
      createdAt:   auditLogs.createdAt,
    })
    .from(auditLogs)
    .where(companyId ? eq(auditLogs.companyId, companyId) : isNull(auditLogs.companyId))
    .orderBy(auditLogs.chainIndex);

  if (rows.length === 0) {
    return { valid: true, totalEntries: 0, brokenAtIndex: null, message: "Chain is empty — no entries yet" };
  }

  let expectedPrevHash = "GENESIS";

  for (const row of rows) {
    if (row.prevHash !== expectedPrevHash) {
      return {
        valid:         false,
        totalEntries:  rows.length,
        brokenAtIndex: row.chainIndex,
        message:       `Chain broken at index ${row.chainIndex}: prev_hash mismatch`,
      };
    }

    const hashInput = [
      row.id,
      row.userId ?? "system",
      row.action,
      row.afterState ?? "",
      row.prevHash,
      row.createdAt instanceof Date ? row.createdAt.toISOString() : row.createdAt,
    ].join("|");
    const expectedHash = sha256(hashInput);

    if (row.entryHash !== expectedHash) {
      return {
        valid:         false,
        totalEntries:  rows.length,
        brokenAtIndex: row.chainIndex,
        message:       `Chain broken at index ${row.chainIndex}: entry_hash mismatch (data tampered)`,
      };
    }

    expectedPrevHash = row.entryHash;
  }

  return {
    valid: true,
    totalEntries: rows.length,
    brokenAtIndex: null,
    message: `Chain intact — ${rows.length} entries verified`,
  };
}

// ============================================================
// AUTH SERVICE — PostgreSQL 16 / Drizzle ORM
// bcrypt password hashing and account lockout logic.
// ============================================================

import bcrypt from "bcryptjs";
import { db } from "../db/connection.ts";
import { users } from "../db/schema/index.ts";
import { eq } from "drizzle-orm";

const BCRYPT_ROUNDS   = parseInt(process.env["BCRYPT_ROUNDS"] ?? "12", 10);
const MAX_ATTEMPTS    = 5;
const LOCKOUT_MINUTES = 30;

export interface HashResult {
  hash: string;
  salt: string;
}

// ── Hash a plain-text password ───────────────────────────────
export async function hashPassword(plain: string): Promise<HashResult> {
  const salt = await bcrypt.genSalt(BCRYPT_ROUNDS);
  const hash = await bcrypt.hash(plain, salt);
  return { hash, salt };
}

// ── Verify a password against a stored hash ──────────────────
export async function verifyPassword(plain: string, hash: string): Promise<boolean> {
  return bcrypt.compare(plain, hash);
}

// ── Record a failed login attempt ────────────────────────────
export async function recordFailedAttempt(userId: string): Promise<void> {
  const [user] = await db
    .select({ failedAttempts: users.failedAttempts })
    .from(users)
    .where(eq(users.id, userId))
    .limit(1);

  if (!user) return;

  const newCount = (user.failedAttempts ?? 0) + 1;
  const now = new Date();

  if (newCount >= MAX_ATTEMPTS) {
    const lockedUntil = new Date(Date.now() + LOCKOUT_MINUTES * 60 * 1000);
    await db.update(users)
      .set({
        failedAttempts: newCount,
        isLocked:       true,
        lockedUntil,
        updatedAt:      now,
      })
      .where(eq(users.id, userId));
  } else {
    await db.update(users)
      .set({
        failedAttempts: newCount,
        updatedAt:      now,
      })
      .where(eq(users.id, userId));
  }
}

// ── Reset failed attempts on successful login ────────────────
export async function resetFailedAttempts(userId: string): Promise<void> {
  const now = new Date();
  await db.update(users)
    .set({
      failedAttempts: 0,
      isLocked:       false,
      lockedUntil:    null,
      lastLoginAt:    now,
      updatedAt:      now,
    })
    .where(eq(users.id, userId));
}

// ── Check if account is currently locked ─────────────────────
export async function isAccountLocked(
  userId: string
): Promise<{ locked: boolean; until: string | null }> {
  const [user] = await db
    .select({ isLocked: users.isLocked, lockedUntil: users.lockedUntil })
    .from(users)
    .where(eq(users.id, userId))
    .limit(1);

  if (!user) return { locked: false, until: null };
  if (!user.isLocked) return { locked: false, until: null };

  // Auto-expire: if lockout time has passed, release the lock
  if (user.lockedUntil && user.lockedUntil <= new Date()) {
    await db.update(users)
      .set({
        isLocked:       false,
        lockedUntil:    null,
        failedAttempts: 0,
        updatedAt:      new Date(),
      })
      .where(eq(users.id, userId));
    return { locked: false, until: null };
  }

  return {
    locked: true,
    until:  user.lockedUntil ? user.lockedUntil.toISOString() : null,
  };
}

// ── Manually unlock account (super_admin action) ─────────────
export async function unlockAccount(userId: string): Promise<void> {
  await db.update(users)
    .set({
      isLocked:       false,
      lockedUntil:    null,
      failedAttempts: 0,
      updatedAt:      new Date(),
    })
    .where(eq(users.id, userId));
}

// ── Force password change flag ────────────────────────────────
export async function requirePasswordChange(userId: string): Promise<void> {
  await db.update(users)
    .set({ mustChangePassword: true, updatedAt: new Date() })
    .where(eq(users.id, userId));
}

// ── Update last login IP ──────────────────────────────────────
export async function updateLastLogin(userId: string, ip: string): Promise<void> {
  const now = new Date();
  await db.update(users)
    .set({ lastLoginAt: now, lastLoginIp: ip, updatedAt: now })
    .where(eq(users.id, userId));
}

export interface LoginResult {
  success:  boolean;
  error?:    "INVALID_CREDENTIALS" | "ACCOUNT_DEACTIVATED" | "ACCOUNT_LOCKED";
  until?:    string | null;
  userId?:   string;
  username?: string;
}

// ── Main Login logic ──────────────────────────────────────────
export async function login(
  username:  string,
  password:  string,
  _ip:       string
): Promise<LoginResult> {
  const [user] = await db
    .select({
      id:           users.id,
      username:     users.username,
      passwordHash: users.passwordHash,
      isActive:     users.isActive,
    })
    .from(users)
    .where(eq(users.username, username))
    .limit(1);

  if (!user) {
    await verifyPassword(password, DUMMY_HASH);
    return { success: false, error: "INVALID_CREDENTIALS" };
  }

  if (!user.isActive) {
    return { success: false, error: "ACCOUNT_DEACTIVATED" };
  }

  const lockStatus = await isAccountLocked(user.id);
  if (lockStatus.locked) {
    return { success: false, error: "ACCOUNT_LOCKED", until: lockStatus.until };
  }

  const valid = await verifyPassword(password, user.passwordHash);
  if (!valid) {
    await recordFailedAttempt(user.id);
    return { success: false, error: "INVALID_CREDENTIALS" };
  }

  await resetFailedAttempts(user.id);
  return { success: true, userId: user.id, username: user.username };
}

// ── Timing Attack Mitigation ──────────────────────────────────
export const DUMMY_HASH =
  "$2b$12$invalidhashfortimingprotectiononly000000000000000000000";

import { BackupService } from './BackupService.ts';
import { db } from '../../db/connection.ts';
import { systemConfig, auditLogs } from '../../db/schema/index.ts';
import { createAuditEntry } from '../audit.service.ts';
import { eq, sql } from 'drizzle-orm';

export interface LastBackupInfo {
  filename: string | null;
  date: string | null;
  status: 'success' | 'failed' | 'none';
  scheduledHourUTC: number | null;
}

export class BackupScheduler {
  private timer: Timer | null = null;
  private backupService: BackupService;

  constructor() {
    this.backupService = new BackupService();
  }

  async start(): Promise<void> {
    this.timer = setInterval(() => this.checkSchedule(), 60 * 60 * 1000);
    try {
      await this.checkSchedule(); // check on start
    } catch (e) {
      console.error("[BackupScheduler] Error during initial checkSchedule:", e);
    }
  }

  async stop(): Promise<void> {
    if (this.timer) clearInterval(this.timer);
  }

  private async checkSchedule() {
    try {
      const [row] = await db.select({ backupScheduleHour: systemConfig.backupScheduleHour }).from(systemConfig).limit(1);
      if (!row || row.backupScheduleHour === null) return;

      const hourUTC = row.backupScheduleHour;
      const currentHour = new Date().getUTCHours();

      if (currentHour === hourUTC) {
         const [ranToday] = await db.execute(sql`
           SELECT 1 as ran FROM audit_logs
           WHERE action IN ('backup:success', 'backup:failed')
             AND DATE(created_at AT TIME ZONE 'UTC') = CURRENT_DATE
           LIMIT 1
         `) as { ran: number }[];

         if (!ranToday) {
             console.log("[Backup] Starting scheduled backup.");
             await this.runScheduledBackup();
         }
      }
    } catch (e) {
      console.error("[Backup] Scheduled check error: ", e);
    }
  }

  private async runScheduledBackup() {
    const tempPassword = process.env.AUTO_BACKUP_SECRET;
    if (!tempPassword) {
      console.error("[BackupScheduler] AUTO_BACKUP_SECRET not set — scheduled backup aborted.");
      return;
    }
    let filename = "";
    try {
      const result = await this.backupService.createBackup(tempPassword);
      filename = result.filename;
      await this.backupService.pruneOldBackups(30);

      await createAuditEntry({
        companyId: null,
        userId: null,
        sessionId: null,
        action: 'backup:success',
        module: 'system',
        entityType: 'backup',
        entityId: null,
        beforeState: null,
        afterState: { filename },
        ipAddress: '127.0.0.1'
      });

    } catch (e: any) {
      await createAuditEntry({
        companyId: null,
        userId: null,
        sessionId: null,
        action: 'backup:failed',
        module: 'system',
        entityType: 'backup',
        entityId: null,
        beforeState: null,
        afterState: { error: e.message },
        ipAddress: '127.0.0.1'
      });
    }
  }

  async runNow(password: string): Promise<void> {
    await this.backupService.createBackup(password);
    await this.backupService.pruneOldBackups(30);
  }

  async setSchedule(hourUTC: number): Promise<void> {
    // Requires an initial row to update, assuming systemConfig has one.
    await db.update(systemConfig).set({ backupScheduleHour: hourUTC });
  }

  async getLastBackupInfo(): Promise<LastBackupInfo> {
    const backups = await this.backupService.listBackups(1);
    let filename: string | null = null;
    let date: string | null = null;
    let status: 'success' | 'failed' | 'none' = 'none';

    if (backups.length > 0) {
      filename = backups[0].filename;
      date = backups[0].createdAt;
      status = 'success';
    }

    let scheduledHourUTC: number | null = null;
    try {
      const [row] = await db.select({ backupScheduleHour: systemConfig.backupScheduleHour }).from(systemConfig).limit(1);
      if (row && row.backupScheduleHour !== null) {
        scheduledHourUTC = row.backupScheduleHour;
      }
    } catch (e) {}

    return { filename, date, status, scheduledHourUTC };
  }

  async getNextBackupTime(): Promise<string> {
     const info = await this.getLastBackupInfo();
     if (info.scheduledHourUTC === null) return "Nunca";
     return `Cada día a las ${info.scheduledHourUTC.toString().padStart(2, '0')}:00 UTC`;
  }
}

import { encryptFile, decryptFile, hashFile } from './crypto.service';
import { readdir, stat, unlink, mkdir, rename } from 'fs/promises';
import { join } from 'path';
import { spawn } from 'child_process';
import { createHash } from 'crypto';
import { createGzip, gunzipSync } from 'zlib';
import { promisify } from 'util';
import { pipeline } from 'stream';
import { createReadStream, createWriteStream } from 'fs';

const pipelineAsync = promisify(pipeline);

export interface BackupResult {
  filename: string;
  size: number;
}

export interface BackupMetadata {
  filename: string;
  size: number;
  createdAt: string;
  auditHash: string;
}

export interface RestoreResult {
  success: boolean;
  message: string;
}

export interface ValidationResult {
  valid: boolean;
  metadata?: any;
}

const BACKUPS_DIR = 'data/backups';
const PG_DUMP_PATH = process.env.PG_DUMP_PATH ?? 'pg_dump';
const PSQL_PATH    = process.env.PSQL_PATH    ?? 'psql';

export class BackupService {
  constructor() {
    this.ensureDir();
  }

  private async ensureDir() {
    try {
      await mkdir(BACKUPS_DIR, { recursive: true });
    } catch {}
  }

  /**
   * Helper síncrono para calcular el hash de un Buffer.
   * Utiliza el módulo nativo 'crypto' de Node.js.
   */
  private computeHash(data: Buffer): string {
    return createHash('sha256').update(data).digest('hex');
  }

  /**
   * Ejecuta pg_dump para crear un archivo SQL y luego lo encripta.
   */
  async createBackup(password: string): Promise<BackupResult> {
    if (!password || password.trim().length < 8) {
      throw new Error("La contraseña del backup debe tener al menos 8 caracteres.");
    }

    await this.ensureDir();
    const now = new Date();
    const dateStr = now.toISOString().replace(/[:.]/g, '-').slice(0, 19);
    const filename = `backup-${dateStr}.sql.gz.enc`;
    const outputPath = join(BACKUPS_DIR, filename);
    const tempSqlPath = join(BACKUPS_DIR, `temp-${dateStr}.sql`);
    const tempGzPath  = join(BACKUPS_DIR, `temp-${dateStr}.sql.gz`);

    const dbUrl = process.env.DATABASE_URL;
    if (!dbUrl) throw new Error("DATABASE_URL no está configurada.");

    // 1. Ejecutar pg_dump y guardar en archivo temporal
    await new Promise<void>((resolve, reject) => {
      const dumpProcess = spawn(PG_DUMP_PATH, [dbUrl, '--format=plain', '--file=' + tempSqlPath]);

      dumpProcess.on('close', (code) => {
        if (code === 0) resolve();
        else reject(new Error(`pg_dump falló con código ${code}`));
      });

      dumpProcess.on('error', (err) => reject(err));
    });

    // 2. Comprimir el SQL con gzip
    await pipelineAsync(
      createReadStream(tempSqlPath),
      createGzip({ level: 6 }),
      createWriteStream(tempGzPath)
    );
    await unlink(tempSqlPath);

    // 3. Calcular hash de integridad ANTES de encriptar
    const auditHash = await hashFile(tempGzPath);

    // 4. Encriptar el archivo comprimido con el hash en los metadatos
    const encryptedPath = await encryptFile(tempGzPath, password, {
      createdAt: now.toISOString(),
      auditHash,
      format: 'postgresql-gzip'
    });

    // 5. Mover al destino final y limpiar archivos temporales
    await rename(encryptedPath, outputPath);
    await unlink(tempGzPath);

    const fileStat = await stat(outputPath);
    return {
      filename,
      size: fileStat.size
    };
  }

  /**
   * Lista los backups filtrando por .sql.enc
   */
  async listBackups(limit: number = 30): Promise<BackupMetadata[]> {
    await this.ensureDir();
    const files = await readdir(BACKUPS_DIR);
    const backups: BackupMetadata[] = [];

    for (const file of files) {
      if (!file.endsWith('.sql.gz.enc') && !file.endsWith('.sql.enc')) continue;
      const fullPath = join(BACKUPS_DIR, file);
      const fileStat = await stat(fullPath);

      const parts = file.replace('backup-', '').replace('.sql.enc', '').split('-');
      let createdAt = fileStat.mtime.toISOString();
      if (parts.length >= 6) {
        createdAt = `${parts[0]}-${parts[1]}-${parts[2]}T${parts[3]}:${parts[4]}:${parts[5]}.000Z`;
      }

      // Intentamos validar/extraer metadatos para obtener el hash real si es necesario,
      // pero por performance en el listado solemos dejarlo como "encrypted" o leerlo de un cache.
      backups.push({
        filename: file,
        size: fileStat.size,
        createdAt,
        auditHash: "encrypted" 
      });
    }

    backups.sort((a, b) => new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime());
    return backups.slice(0, limit);
  }

  /**
   * Desencripta el backup, verifica integridad y lo inyecta vía stdin a psql.exe
   */
  async restoreBackup(filename: string, password: string): Promise<RestoreResult> {
    const fullPath = join(BACKUPS_DIR, filename);
    const dbUrl = process.env.DATABASE_URL;
    if (!dbUrl) throw new Error("DATABASE_URL no está configurada.");

    // 1. Decriptar y obtener datos + metadatos
    const { data, metadata } = await decryptFile(fullPath, password);

    // 2. Verificar integridad del hash
    const currentHash = this.computeHash(data);
    if (currentHash !== metadata.auditHash) {
      throw new Error(`Error de integridad: El hash del backup (${currentHash}) no coincide con el original (${metadata.auditHash}).`);
    }

    // 3. Descomprimir si el backup es formato gzip
    let sqlData = data;
    if (metadata.format === 'postgresql-gzip') {
      sqlData = Buffer.from(gunzipSync(data));
    }

    // 4. Inyectar en psql vía stdin
    await new Promise<void>((resolve, reject) => {
      const psqlProcess = spawn(PSQL_PATH, [dbUrl, '--single-transaction']);

      psqlProcess.stdin.write(sqlData);
      psqlProcess.stdin.end();

      psqlProcess.on('close', (code) => {
        if (code === 0) resolve();
        else reject(new Error(`psql falló con código ${code}`));
      });

      psqlProcess.on('error', (err) => reject(err));
    });

    return { success: true, message: "Base de datos PostgreSQL restaurada e íntegra." };
  }

  async pruneOldBackups(keepCount: number = 30): Promise<void> {
    const backups = await this.listBackups(1000);
    if (backups.length <= keepCount) return;

    const toDelete = backups.slice(keepCount);
    for (const b of toDelete) {
      await unlink(join(BACKUPS_DIR, b.filename)).catch(() => {});
    }
  }

  async exportBackup(filename: string): Promise<string> {
    const fullPath = join(BACKUPS_DIR, filename);
    await stat(fullPath);
    return fullPath;
  }

  async validateBackup(filename: string, password: string): Promise<ValidationResult> {
    const fullPath = join(BACKUPS_DIR, filename);
    try {
      const { metadata } = await decryptFile(fullPath, password);
      return { valid: true, metadata };
    } catch (e) {
      return { valid: false };
    }
  }
}

import { readFile, writeFile } from 'fs/promises';

const MAGIC = new TextEncoder().encode("AEX1");

async function deriveKey(password: string, salt: Uint8Array): Promise<CryptoKey> {
  const enc = new TextEncoder();
  const keyMaterial = await crypto.subtle.importKey(
    "raw",
    enc.encode(password),
    { name: "PBKDF2" },
    false,
    ["deriveBits", "deriveKey"]
  );

  return crypto.subtle.deriveKey(
    {
      name: "PBKDF2",
      salt: salt as any,
      iterations: 210000,
      hash: "SHA-256"
    },
    keyMaterial,
    { name: "AES-GCM", length: 256 },
    true,
    ["encrypt", "decrypt"]
  );
}

export async function encryptFile(inputPath: string, password: string, metadata: object): Promise<string> {
  const fileData = await readFile(inputPath);

  const metaStr = JSON.stringify(metadata);
  const metaBytes = new TextEncoder().encode(metaStr);

  const metaLenBytes = new Uint8Array(4);
  new DataView(metaLenBytes.buffer).setUint32(0, metaBytes.length, true);

  const payload = new Uint8Array(metaLenBytes.length + metaBytes.length + fileData.length);
  payload.set(metaLenBytes, 0);
  payload.set(metaBytes, metaLenBytes.length);
  payload.set(new Uint8Array(fileData), metaLenBytes.length + metaBytes.length);

  const salt = crypto.getRandomValues(new Uint8Array(32));
  const iv = crypto.getRandomValues(new Uint8Array(12));

  const key = await deriveKey(password, salt);

  const encryptedBuffer = await crypto.subtle.encrypt(
    {
      name: "AES-GCM",
      iv: iv as any
    },
    key,
    payload
  );

  const encryptedPayload = new Uint8Array(encryptedBuffer);

  const output = new Uint8Array(MAGIC.length + salt.length + iv.length + encryptedPayload.length);
  output.set(MAGIC, 0);
  output.set(salt, MAGIC.length);
  output.set(iv, MAGIC.length + salt.length);
  output.set(encryptedPayload, MAGIC.length + salt.length + iv.length);

  const outputPath = `${inputPath}.enc`;
  await writeFile(outputPath, output);
  return outputPath;
}

export async function decryptFile(inputPath: string, password: string): Promise<{data: Buffer, metadata: any}> {
  const file = await readFile(inputPath);
  const data = new Uint8Array(file);

  const magic = data.slice(0, 4);
  const magicStr = new TextDecoder().decode(magic);
  if (magicStr !== "AEX1") {
    throw new Error("Formato de backup inválido.");
  }

  const salt = data.slice(4, 36);
  const iv = data.slice(36, 48);
  const encryptedPayload = data.slice(48);

  const key = await deriveKey(password, salt);

  let decryptedBuffer: ArrayBuffer;
  try {
    decryptedBuffer = await crypto.subtle.decrypt(
      {
        name: "AES-GCM",
        iv: iv as any
      },
      key,
      encryptedPayload
    );
  } catch (err) {
    throw new Error("Contraseña incorrecta o archivo corrupto.");
  }

  const decryptedData = new Uint8Array(decryptedBuffer);
  const metaLen = new DataView(decryptedData.slice(0, 4).buffer).getUint32(0, true);

  const metaBytes = decryptedData.slice(4, 4 + metaLen);
  const metaStr = new TextDecoder().decode(metaBytes);
  const metadata = JSON.parse(metaStr);

  const fileData = decryptedData.slice(4 + metaLen);
  return {
    data: Buffer.from(fileData),
    metadata
  };
}

export async function hashFile(filePath: string): Promise<string> {
  const fileBuffer = await readFile(filePath);
  const hashBuffer = await crypto.subtle.digest("SHA-256", fileBuffer);
  const hashArray = Array.from(new Uint8Array(hashBuffer));
  return hashArray.map(b => b.toString(16).padStart(2, '0')).join('');
}

// ============================================================
// BANK CSV IMPORT SERVICE — PostgreSQL 16 / Drizzle ORM
// Ingests CSV extracts from Chase, BofA, WellsFargo and Generic.
// Provides mechanical deterministic duplicate prevention.
// ============================================================

import { db } from "../../db/connection.ts";
import { bankTransactions } from "../../db/schema/index.ts";
import { v4 as uuidv4 } from "uuid";
import { and, eq } from "drizzle-orm";

export interface ParsedTransaction {
  date: string;       // YYYY-MM-DD
  description: string;
  amount: number;     // Negative = expense, Positive = deposit
  reference: string | null;
}

export interface ParseResult {
  transactions: ParsedTransaction[];
  format: string;
  failedRows: number;
}

// ── Date normalizer — handles all US bank date formats ───────
export function normalizeDate(raw: string): string {
  if (!raw) return new Date().toISOString().split("T")[0];
  const s = raw.trim();

  // Already ISO: YYYY-MM-DD
  if (/^\d{4}-\d{2}-\d{2}/.test(s)) return s.substring(0, 10);

  // MM/DD/YYYY or MM-DD-YYYY
  const parts = s.split(/[\/\-]/);
  if (parts.length === 3) {
    let [a, b, c] = parts;
    if (c.length === 2) c = "20" + c; // 2-digit year
    if (c.length === 4) {
      // MM/DD/YYYY
      return `${c}-${a.padStart(2, "0")}-${b.padStart(2, "0")}`;
    }
  }

  // Fallback: try native Date parser
  const d = new Date(s);
  if (!isNaN(d.getTime())) return d.toISOString().split("T")[0];

  return new Date().toISOString().split("T")[0];
}

// ── CSV line splitter — respects quoted commas ───────────────
function splitCsvLine(line: string): string[] {
  return line
    .split(/,(?=(?:(?:[^"]*"){2})*[^"]*$)/)
    .map(s => s.replace(/^"|"$/g, "").trim());
}

// ── Detect Wells Fargo: no header, cols are Date,Amt,*,*,Desc ─
function isWellsFargoFormat(lines: string[]): boolean {
  if (lines.length < 2) return false;
  const first = splitCsvLine(lines[0]);
  if (first.length < 5) return false;
  const dateOk = /^\d{1,2}[\/\-]\d{1,2}[\/\-]\d{2,4}$/.test(first[0].trim());
  const amtOk  = !isNaN(parseFloat(first[1].replace(/[^0-9.\-]/g, "")));
  return dateOk && amtOk;
}

// ── Deterministic CSV Parser ─────────────────────────────────
export function parseBankCsv(csvText: string): ParseResult {
  const lines = csvText.split(/\r?\n/).map(l => l.trim()).filter(l => l.length > 0);
  if (lines.length === 0) return { transactions: [], format: "empty", failedRows: 0 };

  const headerRaw = lines[0].toLowerCase();
  let format = "generic";
  let startIndex = 1;
  let failedRows = 0;

  // Format detection
  if (headerRaw.includes("check or slip #") || headerRaw.includes("details,posting date")
    || (headerRaw.includes("transaction date") && headerRaw.includes("post date"))) {
    format = "chase";
  } else if (headerRaw.includes("running bal") || 
    (headerRaw.startsWith("date") && headerRaw.includes("description") && headerRaw.includes("amount"))) {
    format = "bofa";
  } else if (isWellsFargoFormat(lines)) {
    format = "wellsfargo";
    startIndex = 0;
  }

  const results: ParsedTransaction[] = [];

  for (let i = startIndex; i < lines.length; i++) {
    const row = splitCsvLine(lines[i]);
    try {
      let tx: ParsedTransaction | null = null;

      if (format === "chase" && row.length >= 4) {
        const amt = parseFloat(row[3].replace(/[^0-9.\-]/g, "") || "0");
        if (isNaN(amt)) { failedRows++; continue; }
        tx = { date: normalizeDate(row[1]), description: row[2] || "Unknown", amount: amt, reference: row[6] ?? null };
      } else if (format === "bofa" && row.length >= 3) {
        const amt = parseFloat(row[2].replace(/[^0-9.\-]/g, "") || "0");
        if (isNaN(amt)) { failedRows++; continue; }
        tx = { date: normalizeDate(row[0]), description: row[1] || "Unknown", amount: amt, reference: null };
      } else if (format === "wellsfargo" && row.length >= 5) {
        const amt = parseFloat(row[1].replace(/[^0-9.\-]/g, "") || "0");
        if (isNaN(amt)) { failedRows++; continue; }
        tx = { date: normalizeDate(row[0]), description: row[4] || "Unknown", amount: amt, reference: null };
      } else if (row.length >= 3) {
        const amt = parseFloat(row[2].replace(/[^0-9.\-]/g, "") || "0");
        if (isNaN(amt)) { failedRows++; continue; }
        tx = { date: normalizeDate(row[0]), description: row[1] || "Unknown", amount: amt, reference: null };
      } else {
        failedRows++;
        continue;
      }

      if (tx && tx.amount !== 0) results.push(tx);
    } catch {
      failedRows++;
    }
  }

  return { transactions: results, format, failedRows };
}

// ── Native SQL Duplicate Resolver ────────────────────────────
export async function importTransactions(
  companyId: string,
  bankAccount: string,
  csvText: string
): Promise<{ imported: number; duplicates: number; failedRows: number; batchId: string; format: string }> {
  const { transactions: parsed, format, failedRows } = parseBankCsv(csvText);
  if (parsed.length === 0) return { imported: 0, duplicates: 0, failedRows, batchId: "", format };

  const batchId = uuidv4();
  const now = new Date();
  let imported = 0;
  let duplicates = 0;

  await db.transaction(async (tx) => {
    for (const p of parsed) {
      const [exists] = await tx
        .select({ id: bankTransactions.id })
        .from(bankTransactions)
        .where(
          and(
            eq(bankTransactions.companyId, companyId),
            eq(bankTransactions.bankAccount, bankAccount),
            eq(bankTransactions.transactionDate, p.date),
            eq(bankTransactions.amount, String(p.amount)),
            eq(bankTransactions.description, p.description)
          )
        )
        .limit(1);

      if (exists) {
        duplicates++;
      } else {
        await tx.insert(bankTransactions).values({
          id:              uuidv4(),
          companyId,
          bankAccount,
          transactionDate: p.date,
          description:     p.description,
          amount:          String(p.amount),
          transactionType: p.amount < 0 ? "debit" : "credit",
          referenceNumber: p.reference,
          status:          "pending",
          importBatchId:   batchId,
          createdAt:       now,
        });
        imported++;
      }
    }
  });

  return { imported, duplicates, failedRows, batchId, format };
}

// ============================================================
// RECONCILIATION SERVICE
// Translates abstract Bank Transactions into rigorous
// Double-Entry Journal Entries automatically.
// PostgreSQL 16 / Drizzle ORM
// ============================================================

import { db } from "../../db/connection.ts";
import { bankTransactions } from "../../db/schema/index.ts";
import { eq, and } from "drizzle-orm";
import { createDraft, post, ValidationError } from "../journal.service.ts";
import { v4 as uuidv4 } from "uuid";

// ── Perform Bank Reconciliation ─────────────────────────────
export async function matchTransaction(
  companyId: string,
  transactionId: string,
  accountId: string,   // Target specific COA (e.g., Office Supplies)
  bankAccountId: string, // The actual Bank COA (e.g., 1010 Cash)
  periodId: string,
  userId: string,
  sessionId: string,
  ipAddress: string
): Promise<string> {
  return await db.transaction(async (tx) => {
    // 1. Validate Transaction
    const [transaction] = await tx
      .select()
      .from(bankTransactions)
      .where(
        and(
          eq(bankTransactions.id, transactionId),
          eq(bankTransactions.companyId, companyId)
        )
      )
      .limit(1);

    if (!transaction) throw new ValidationError("Transacción bancaria no encontrada.");
    if (transaction.status === "reconciled") throw new ValidationError("La transacción ya se encuentra conciliada.");

    // 2. Draft double-entry lines
    const txAmountNum = Number(transaction.amount);
    const absAmount = Math.abs(txAmountNum);

    // Default US GAAP perspective
    // Bank outflow (- amount) -> Credit Bank, Debit Expense
    // Bank inflow (+ amount) -> Debit Bank, Credit Revenue
    const bankLine = {
      accountId: bankAccountId,
      debitAmount:  txAmountNum > 0 ? absAmount : 0,
      creditAmount: txAmountNum < 0 ? absAmount : 0,
      lineNumber: 1,
      description: `Ref: ${transaction.description}`
    };

    const targetLine = {
      accountId: accountId,
      debitAmount:  txAmountNum < 0 ? absAmount : 0,
      creditAmount: txAmountNum > 0 ? absAmount : 0,
      lineNumber: 2,
      description: `Reconciliación: ${transaction.description}`
    };

    // 3. Dispatch Journal Drafting
    const draftId = await createDraft({
      companyId,
      entryDate: transaction.transactionDate,
      description: `Conciliación Bancaria: ${transaction.description}`,
      reference: transaction.referenceNumber || null,
      isAdjusting: false,
      periodId,
      createdBy: userId
    }, [bankLine, targetLine]); // pass tx here to keep transaction bound

    // 4. Force strict double-entry verification via Post() mechanically
    await post(draftId, userId, sessionId, ipAddress); // pass tx here as well

    // 5. Hard link completion to the Bank state
    await tx.update(bankTransactions)
      .set({
        status: 'reconciled',
        journalEntryId: draftId,
        matchedBy: userId,
        matchedAt: new Date()
      })
      .where(eq(bankTransactions.id, transactionId));

    return draftId;
  });
}

// ── Ignore Bank Transaction ─────────────────────────────────
export async function ignoreTransaction(
  companyId: string,
  transactionId: string,
  userId: string,
  ipAddress: string
): Promise<void> {
  await db.transaction(async (tx) => {
    const [transaction] = await tx
      .select()
      .from(bankTransactions)
      .where(
        and(
          eq(bankTransactions.id, transactionId),
          eq(bankTransactions.companyId, companyId)
        )
      )
      .limit(1);

    if (!transaction) throw new ValidationError("Transacción bancaria no encontrada.");
    if (transaction.status !== "pending") throw new ValidationError("Sólo las transacciones pendientes pueden ser ignoradas.");

    await tx.update(bankTransactions)
      .set({
        status: 'ignored',
        matchedBy: userId,
        matchedAt: new Date()
      })
      .where(eq(bankTransactions.id, transactionId));
  });
}

import { db } from "../../db/connection";
import { bankTransactions } from "../../db/schema/accounting.schema";
import { bankAccounts } from "../../db/schema/bank-accounts.schema";
import { and, eq } from "drizzle-orm";
import { randomUUID } from "node:crypto";

export interface ParsedTransaction {
    date: string;
    description: string;
    amount: number;
    referenceNumber?: string;
}

export interface ImportResult {
    batchId: string;
    totalParsed: number;
    importedCount: number;
    duplicateCount: number;
    format: string;
    extractedBankName?: string;
}

function parseCSVLine(line: string): string[] {
    const regex = /,(?=(?:(?:[^"]*"){2})*[^"]*$)/;
    return line.split(regex).map(col => col.replace(/^"|"$/g, '').trim());
}

function normalizeDate(rawDate: string): string {
    // rawDate can be MM/DD/YYYY, YYYY-MM-DD, etc.
    // Ensure ISO 8601 YYYY-MM-DD.
    if (!rawDate) return new Date().toISOString().split('T')[0];

    // YYYY-MM-DD
    if (/^\d{4}-\d{2}-\d{2}/.test(rawDate)) {
        return rawDate.substring(0, 10);
    }

    // MM/DD/YYYY or MM-DD-YYYY or M/D/YY
    const parts = rawDate.split(/[\/\-]/);
    if (parts.length === 3) {
        let m = parts[0].padStart(2, '0');
        let d = parts[1].padStart(2, '0');
        let y = parts[2];
        if (y.length === 2) y = '20' + y;
        return `${y}-${m}-${d}`;
    }

    // Fallback
    const d = new Date(rawDate);
    if (!isNaN(d.getTime())) {
        return d.toISOString().split('T')[0];
    }

    return new Date().toISOString().split('T')[0];
}

class StatementImportService {
    async processFile(companyId: string, bankAccountName: string, fileBuffer: Buffer, fileName: string): Promise<ImportResult> {
        const content = fileBuffer.toString('utf-8');
        const extension = fileName.split('.').pop()?.toLowerCase();

        let txns: ParsedTransaction[] = [];
        let format = "unknown";
        let extractedBankName: string | undefined;

        if (extension === 'csv') {
            const lines = content.split('\n').filter(l => l.trim().length > 0);
            if (lines.length > 0) {
                const header = lines[0].toLowerCase();

                // Detect Chase
                const cols = header.split(',').map((c: string) => c.trim());
                const hasTransactionDate = cols.some((c: string) => c === "transaction date");
                const hasPostDate = cols.some((c: string) => c === "post date");

                if (hasTransactionDate && hasPostDate) {
                    format = "CSV-Chase";
                    extractedBankName = "CHASE";
                    txns = this.parseChaseCSV(lines);
                }
                // Detect BofA
                else if (header.includes("date") && header.includes("description") && header.includes("amount") && header.includes("running bal")) {
                    format = "CSV-BofA";
                    extractedBankName = "Bank of America";
                    txns = this.parseBofaCSV(lines);
                }
                // Detect Generic or Wells Fargo
                else if (header.includes("date") && header.includes("amount") && header.includes("description")) {
                    format = "CSV-Generic";
                    txns = this.parseGenericCSV(lines);
                } 
                else {
                    // Try generic index heuristic if column names are weird
                    format = "CSV-Fallback";
                    txns = this.parseGenericCSV(lines);
                }
            }
        } else if (extension === 'ofx' || extension === 'qfx') {
            format = extension.toUpperCase();
            txns = this.parseOFX(content);
            const orgMatch = content.match(/<ORG>(.*?)(?:<|\r|\n)/);
            if (orgMatch && orgMatch[1]) {
                extractedBankName = orgMatch[1].trim();
            }
        } else {
            throw new Error("Formato de archivo no soportado. Debe ser CSV, OFX o QFX.");
        }

        let matchingAccountId = bankAccountName;

        if (!matchingAccountId && extractedBankName) {
            const accs = await db.select().from(bankAccounts)
                .where(and(eq(bankAccounts.companyId, companyId), eq(bankAccounts.bankName, extractedBankName), eq(bankAccounts.isActive, true)))
                .limit(1);
            if (accs.length > 0) matchingAccountId = accs[0].id;
        }

        if (!matchingAccountId) {
            throw new Error(JSON.stringify({ code: 'UNKNOWN_BANK', bankName: extractedBankName || 'Desconocido' }));
        }

        const batchId = randomUUID();
        let imported = 0;
        let duplicates = 0;

        for (const t of txns) {
            // Deduplication check
            const existing = await db.select({ id: bankTransactions.id })
                .from(bankTransactions)
                .where(
                    and(
                        eq(bankTransactions.companyId, companyId),
                        eq(bankTransactions.transactionDate, t.date),
                        eq(bankTransactions.description, t.description),
                        eq(bankTransactions.amount, t.amount.toString())
                    )
                ).limit(1);

            if (existing.length > 0) {
                duplicates++;
            } else {
                await db.insert(bankTransactions).values({
                    id: randomUUID(),
                    companyId: companyId,
                    bankAccount: matchingAccountId,
                    transactionDate: t.date,
                    description: t.description,
                    amount: t.amount.toString(),
                    transactionType: t.amount < 0 ? 'debit' : 'credit',
                    referenceNumber: t.referenceNumber || null,
                    status: 'pending',
                    importBatchId: batchId,
                    createdAt: new Date()
                });
                imported++;
            }
        }

        return {
            batchId,
            totalParsed: txns.length,
            importedCount: imported,
            duplicateCount: duplicates,
            format,
            extractedBankName
        };
    }

    private parseChaseCSV(lines: string[]): ParsedTransaction[] {
        // Chase: Details,Posting Date,Description,Amount,Type,Balance,Check or Slip #
        // Or newer: Transaction Date,Post Date,Description,Category,Type,Amount,Memo
        const header = parseCSVLine(lines[0].toLowerCase());
        const dateIdx = header.findIndex(h => h.includes('date') && !h.includes('post'));
        const fallbackDateIdx = header.findIndex(h => h.includes('post date'));
        const descIdx = header.findIndex(h => h.includes('description'));
        const amtIdx = header.findIndex(h => h.includes('amount'));

        const actualDateIdx = dateIdx >= 0 ? dateIdx : (fallbackDateIdx >= 0 ? fallbackDateIdx : 0);

        return this.extractFromCols(lines.slice(1), actualDateIdx, descIdx >= 0 ? descIdx : 2, amtIdx >= 0 ? amtIdx : 3);
    }

    private parseBofaCSV(lines: string[]): ParsedTransaction[] {
        // BofA often skips headers or has "Date, Description, Amount, Running Bal." starting from line 7 or 8.
        const headerLineIndex = lines.findIndex(l => l.toLowerCase().includes('date') && l.toLowerCase().includes('amount'));
        const startIndex = headerLineIndex >= 0 ? headerLineIndex + 1 : 1;

        let header = [];
        if (headerLineIndex >= 0) {
            header = parseCSVLine(lines[headerLineIndex].toLowerCase());
        } else {
            header = parseCSVLine(lines[0].toLowerCase());
        }

        const dateIdx = header.indexOf('date') >= 0 ? header.indexOf('date') : 0;
        const descIdx = header.indexOf('description') >= 0 ? header.indexOf('description') : 1;
        const amtIdx = header.indexOf('amount') >= 0 ? header.indexOf('amount') : 2;

        return this.extractFromCols(lines.slice(startIndex), dateIdx, descIdx, amtIdx);
    }

    private parseGenericCSV(lines: string[]): ParsedTransaction[] {
        const header = parseCSVLine(lines[0].toLowerCase());
        let dateIdx = header.findIndex(h => h.includes('date') || h.includes('fecha'));
        let descIdx = header.findIndex(h => h.includes('description') || h.includes('descripción') || h.includes('memo'));
        let amtIdx = header.findIndex(h => h.includes('amount') || h.includes('monto'));

        if (dateIdx === -1) dateIdx = 0;
        if (descIdx === -1) descIdx = 1;
        if (amtIdx === -1) amtIdx = Math.max(0, header.length - 1);

        // skip header if it contains letters in amount col, else start 0
        const firstDataRow = parseCSVLine(lines[1] || "");
        const startIndex = isNaN(parseFloat((firstDataRow[amtIdx] || "").replace(/[^0-9.-]+/g, ''))) ? 1 : 0;

        return this.extractFromCols(lines.slice(startIndex === 0 ? 0 : 1), dateIdx, descIdx, amtIdx);
    }

    private extractFromCols(dataLines: string[], dateIdx: number, descIdx: number, amtIdx: number): ParsedTransaction[] {
        const txns: ParsedTransaction[] = [];
        for (const line of dataLines) {
            if (!line.trim()) continue;
            const cols = parseCSVLine(line);
            if (cols.length <= Math.max(dateIdx, descIdx, amtIdx)) continue;

            const dateStr = cols[dateIdx];
            const descStr = cols[descIdx];
            const amtStr = cols[amtIdx].replace(/[^0-9.-]+/g, ''); // strip out $ and commas

            if (!dateStr || !amtStr || isNaN(parseFloat(amtStr))) continue;

            txns.push({
                date: normalizeDate(dateStr),
                description: descStr,
                amount: parseFloat(amtStr)
            });
        }
        return txns;
    }

    private parseOFX(content: string): ParsedTransaction[] {
        const txns: ParsedTransaction[] = [];

        // Find all <STMTTRN> blocks
        const blocks = content.split('<STMTTRN>');

        for (let i = 1; i < blocks.length; i++) {
            const block = blocks[i].split('</STMTTRN>')[0];

            // Extracts value between <TAG> and <
            const extractTag = (tag: string) => {
                const parts = block.split(`<${tag}>`);
                if (parts.length > 1) {
                    const val = parts[1].split('<')[0].trim();
                    // Some OFX formats have newlines inside tags, so take the first non-empty sequence
                    return val.split(/\r?\n/)[0].trim();
                }
                return "";
            };

            const dtposted = extractTag('DTPOSTED');
            const trnamt = extractTag('TRNAMT');
            const name = extractTag('NAME');
            const memo = extractTag('MEMO');
            const fitid = extractTag('FITID');

            if (!dtposted || !trnamt) continue;

            // OFX Date is YYYYMMDDHHMMSS...
            let normalizedDate = "";
            if (dtposted.length >= 8) {
                normalizedDate = `${dtposted.substring(0,4)}-${dtposted.substring(4,6)}-${dtposted.substring(6,8)}`;
            } else {
                normalizedDate = new Date().toISOString().split('T')[0];
            }

            const description = name || memo || "Transacción Desconocida";

            txns.push({
                date: normalizedDate,
                amount: parseFloat(trnamt),
                description,
                referenceNumber: fitid || undefined
            });
        }

        return txns;
    }

    async processParsedBatch(
        companyId: string,
        bankAccountId: string | undefined,
        txns: { date: string, description: string, amount: number, balance?: number }[],
        bankName: string | undefined,
        accountNumber: string | undefined,
        batchId: string
    ) {
        let matchingAccountId = bankAccountId;

        if (!matchingAccountId && bankName) {
            const accs = await db.select().from(bankAccounts)
                .where(and(eq(bankAccounts.companyId, companyId), eq(bankAccounts.bankName, bankName), eq(bankAccounts.isActive, true)))
                .limit(1);
            if (accs.length > 0) matchingAccountId = accs[0].id;
        }

        if (!matchingAccountId) {
            throw new Error(JSON.stringify({ code: 'UNKNOWN_BANK', bankName: bankName || 'Desconocido', accountNumber }));
        }

        let imported = 0;
        let duplicates = 0;

        for (const t of txns) {
            const existing = await db.select({ id: bankTransactions.id })
                .from(bankTransactions)
                .where(
                    and(
                        eq(bankTransactions.companyId, companyId),
                        eq(bankTransactions.transactionDate, t.date),
                        eq(bankTransactions.description, t.description),
                        eq(bankTransactions.amount, t.amount.toString())
                    )
                ).limit(1);

            if (existing.length > 0) {
                duplicates++;
            } else {
                await db.insert(bankTransactions).values({
                    id: randomUUID(),
                    companyId: companyId,
                    bankAccount: matchingAccountId,
                    transactionDate: t.date,
                    description: t.description,
                    amount: t.amount.toString(),
                    transactionType: t.amount < 0 ? 'debit' : 'credit',
                    referenceNumber: null,
                    status: 'pending',
                    importBatchId: batchId,
                    createdAt: new Date()
                });
                imported++;
            }
        }

        // Actualizar balance de la cuenta bancaria sumando
        // el neto de las transacciones importadas
        if (imported > 0) {
            const netAmount = txns
              .filter(t => {
                  // Solo las que no son duplicados — aproximación:
                  // recalcular el neto de todas (duplicados ya existían)
                  return true;
              })
              .reduce((sum, t) => sum + t.amount, 0);

            // Traer balance actual
            const acc = await db.select({ balance: bankAccounts.balance })
              .from(bankAccounts)
              .where(eq(bankAccounts.id, matchingAccountId))
              .limit(1);

            if (acc.length > 0) {
                const currentBalance = acc[0].balance || 0;
                // balance se guarda en centavos
                const delta = Math.round(netAmount * 100);
                await db.update(bankAccounts)
                  .set({
                      balance: currentBalance + delta,
                      updatedAt: new Date()
                  })
                  .where(eq(bankAccounts.id, matchingAccountId));
            }
        }

        return {
            batchId,
            totalParsed: txns.length,
            importedCount: imported,
            duplicateCount: duplicates,
            format: 'pdf',
            extractedBankName: bankName
        };
    }
}

export const statementImportService = new StatementImportService();

// ============================================================
// FISCAL PERIOD SERVICE — PostgreSQL 16 / Drizzle ORM
// Controls the open → closed → locked lifecycle per company.
// All functions are async.
// ============================================================

import { db, sql } from "../db/connection.ts";
import { fiscalPeriods, bankTransactions, journalEntries } from "../db/schema/index.ts";
import { eq, and, ne, lte, gte, count } from "drizzle-orm";
import { v4 as uuidv4 } from "uuid";

export type PeriodStatus = "open" | "closed" | "locked";
export type PeriodType   = "monthly" | "quarterly" | "annual";

// ── Create a new fiscal period ───────────────────────────────
export async function openPeriod(opts: {
  companyId:  string;
  name:       string;
  periodType: PeriodType;
  startDate:  string; // ISO 8601 date YYYY-MM-DD
  endDate:    string;
}): Promise<string> {
  // Validate: no overlap with existing active periods of same type
  const [overlapping] = await db.execute(sql`
    SELECT id FROM fiscal_periods
    WHERE company_id  = ${opts.companyId}
      AND period_type = ${opts.periodType}
      AND status NOT IN ('closed', 'locked')
      AND NOT (end_date < ${opts.startDate} OR start_date > ${opts.endDate})
    LIMIT 1
  `) as any[];

  if (overlapping) {
    throw new Error(
      `An active ${opts.periodType} period already exists that overlaps with ` +
      `${opts.startDate} – ${opts.endDate}`
    );
  }

  const id  = uuidv4();
  const now = new Date();

  await db.insert(fiscalPeriods).values({
    id,
    companyId:  opts.companyId,
    name:       opts.name,
    periodType: opts.periodType,
    startDate:  opts.startDate,
    endDate:    opts.endDate,
    status:     "open",
    createdAt:  now,
  });

  return id;
}

// ── Close a period ───────────────────────────────────────────
export async function closePeriod(periodId: string, closedByUserId: string): Promise<void> {
  const period = await getPeriod(periodId);
  if (!period) throw new Error(`Fiscal period ${periodId} not found`);
  if (period.status === "locked") throw new Error("Cannot close a locked period");
  if (period.status === "closed") throw new Error("Period is already closed");

  // Check no pending bank transactions in the period date range
  const [pendingTxResult] = await db
    .select({ c: count() })
    .from(bankTransactions)
    .where(
      and(
        eq(bankTransactions.companyId, period.companyId),
        eq(bankTransactions.status, "pending"),
        gte(bankTransactions.transactionDate, period.startDate),
        lte(bankTransactions.transactionDate, period.endDate)
      )
    );

  const pendingTxCount = pendingTxResult?.c ?? 0;
  if (pendingTxCount > 0) {
    throw new Error(
      `Cannot close period: ${pendingTxCount} bank transaction(s) still pending reconciliation`
    );
  }

  // Check no draft journal entries remain in this period
  const [pendingDraftsResult] = await db
    .select({ c: count() })
    .from(journalEntries)
    .where(
      and(
        eq(journalEntries.periodId, periodId),
        eq(journalEntries.status, "draft")
      )
    );

  const pendingDraftCount = pendingDraftsResult?.c ?? 0;
  if (pendingDraftCount > 0) {
    throw new Error(
      `Cannot close period: ${pendingDraftCount} journal entry/entries ` +
      `still in draft status. Post or delete them before closing.`
    );
  }

  await db.update(fiscalPeriods)
    .set({ status: "closed", closedBy: closedByUserId, closedAt: new Date() })
    .where(eq(fiscalPeriods.id, periodId));
}

// ── Lock a period (terminal — cannot be undone) ──────────────
export async function lockPeriod(periodId: string): Promise<void> {
  const period = await getPeriod(periodId);
  if (!period) throw new Error(`Fiscal period ${periodId} not found`);
  if (period.status === "locked") throw new Error("Period is already locked");
  if (period.status === "open")   throw new Error("Period must be closed before locking");

  await db.update(fiscalPeriods)
    .set({ status: "locked" })
    .where(eq(fiscalPeriods.id, periodId));
}

// ── Get a period by ID ────────────────────────────────────────
export async function getPeriod(periodId: string) {
  const [result] = await db
    .select()
    .from(fiscalPeriods)
    .where(eq(fiscalPeriods.id, periodId))
    .limit(1);
  return result ?? null;
}

// ── Find the open period containing a specific date ──────────
export async function findOpenPeriodForDate(
  companyId: string,
  entryDate: string
): Promise<string> {
  const [period] = await db.execute(sql`
    SELECT id, status FROM fiscal_periods
    WHERE company_id = ${companyId}
      AND start_date <= ${entryDate}
      AND end_date   >= ${entryDate}
    ORDER BY start_date DESC
    LIMIT 1
  `) as any[];

  if (!period) {
    throw new Error(`No fiscal period found covering date ${entryDate} for company ${companyId}`);
  }
  if (period.status !== "open") {
    throw new Error(`The fiscal period covering ${entryDate} is ${period.status} — cannot create entries`);
  }

  return period.id;
}

// ── List periods for a company ────────────────────────────────
export async function listPeriods(companyId: string, status?: PeriodStatus) {
  const conditions = status
    ? and(eq(fiscalPeriods.companyId, companyId), eq(fiscalPeriods.status, status))
    : eq(fiscalPeriods.companyId, companyId);

  return db
    .select()
    .from(fiscalPeriods)
    .where(conditions)
    .orderBy(fiscalPeriods.startDate);
}

// ============================================================
// JOURNAL HASH SERVICE — PostgreSQL 16 / Drizzle ORM
// Cryptographic integrity for the journal entry chain.
// IMPORTANT: nextEntryNumber and getJournalChainTip are async.
// ============================================================

import { createHash }      from "crypto";
import { db, sql }         from "../db/connection.ts";
import { journalEntries }  from "../db/schema/index.ts";
import { eq, desc }        from "drizzle-orm";
import type { JournalEntryInput, JournalLineInput } from "./journal.service.ts";

export function sha256(data: string): string {
  return createHash("sha256").update(data, "utf8").digest("hex");
}

// ── Generate next sequential entry number ───────────────────
export async function nextEntryNumber(companyId: string): Promise<string> {
  // SUBSTR equivalent in PostgreSQL: SPLIT_PART or SUBSTRING
  const [row] = await db.execute(sql`
    SELECT MAX(CAST(SPLIT_PART(entry_number, '-', 3) AS INTEGER)) as max_seq
    FROM journal_entries
    WHERE company_id = ${companyId}
  `) as any[];

  const year = new Date().getFullYear();
  const seq  = String((row?.max_seq ?? 0) + 1).padStart(4, "0");
  return `JE-${year}-${seq}`;
}

// ── Get the hash of the last entry (chain tip) ───────────────
export async function getJournalChainTip(companyId: string): Promise<{ hash: string }> {
  const [row] = await db
    .select({ entryHash: journalEntries.entryHash })
    .from(journalEntries)
    .where(eq(journalEntries.companyId, companyId))
    .orderBy(desc(journalEntries.createdAt))
    .limit(1);

  return { hash: row?.entryHash ?? "GENESIS" };
}

// ── Compute SHA-256 hash for a journal entry ─────────────────
export function computeEntryHash(
  entryId:  string,
  entry:    JournalEntryInput,
  lines:    JournalLineInput[],
  prevHash: string
): string {
  const linesFingerprint = [...lines]
    .sort((a, b) => a.lineNumber - b.lineNumber)
    .map((l) => `${l.accountId}|${l.debitAmount}|${l.creditAmount}`)
    .join(",");

  const data = [
    entryId,
    entry.companyId,
    entry.entryDate,
    entry.description,
    linesFingerprint,
    prevHash,
  ].join("|");

  return sha256(data);
}

// ============================================================
// JOURNAL SERVICE — PostgreSQL 16 / Drizzle ORM
// Core accounting engine: draft creation, posting, queries.
// All functions are async.
// ============================================================

import { db, sql }        from "../db/connection.ts";
import { journalEntries, journalLines, fiscalPeriods } from "../db/schema/index.ts";
import { eq, and, desc }  from "drizzle-orm";
import { createAuditEntry } from "./audit.service.ts";
import { v4 as uuidv4 }   from "uuid";
import { validateDoubleEntry } from "./journal-math.service.ts";
import { nextEntryNumber, getJournalChainTip, computeEntryHash } from "./journal-hash.service.ts";

export interface JournalLineInput {
  accountId:    string;
  debitAmount:  number;
  creditAmount: number;
  description:  string | null;
  lineNumber:   number;
}

export interface JournalEntryInput {
  companyId:   string;
  entryDate:   string;
  description: string;
  reference:   string | null;
  isAdjusting: boolean;
  periodId:    string;
  createdBy:   string;
}

export class ValidationError extends Error {
  constructor(message: string) {
    super(message);
    this.name = "ValidationError";
  }
}

// ── Create a draft journal entry ─────────────────────────────
export async function createDraft(
  entry: JournalEntryInput,
  lines: JournalLineInput[]
): Promise<string> {
  if (lines.length === 0) throw new ValidationError("Al menos una línea es requerida.");

  const [period] = await db
    .select({ status: fiscalPeriods.status })
    .from(fiscalPeriods)
    .where(eq(fiscalPeriods.id, entry.periodId))
    .limit(1);

  if (!period) throw new ValidationError("Periodo fiscal no encontrado.");
  if (period.status === "closed" || period.status === "locked")
    throw new ValidationError("El periodo contable se encuentra cerrado. No se permiten nuevos asientos.");

  const id          = uuidv4();
  const now         = new Date();
  const entryNumber = await nextEntryNumber(entry.companyId);
  const prevHash    = (await getJournalChainTip(entry.companyId)).hash;
  const entryHash   = computeEntryHash(id, entry, lines, prevHash);

  await db.transaction(async (tx) => {
    await tx.insert(journalEntries).values({
      id,
      companyId:   entry.companyId,
      entryNumber,
      entryDate:   entry.entryDate,
      description: entry.description,
      reference:   entry.reference ?? null,
      status:      "draft",
      isAdjusting: entry.isAdjusting,
      isReversing: false,
      periodId:    entry.periodId,
      createdBy:   entry.createdBy,
      entryHash,
      prevHash,
      createdAt:   now,
      updatedAt:   now,
    });

    for (const line of lines) {
      await tx.insert(journalLines).values({
        id:             uuidv4(),
        journalEntryId: id,
        companyId:      entry.companyId,
        accountId:      line.accountId,
        debitAmount:    String(line.debitAmount),
        creditAmount:   String(line.creditAmount),
        description:    line.description ?? null,
        lineNumber:     line.lineNumber,
        createdAt:      now,
      });
    }
  });

  return id;
}

// ── Post a draft journal entry ────────────────────────────────
export async function post(
  entryId:   string,
  postedBy:  string,
  sessionId: string,
  ipAddress: string
): Promise<void> {
  const [entry] = await db
    .select({ companyId: journalEntries.companyId, status: journalEntries.status, periodId: journalEntries.periodId })
    .from(journalEntries)
    .where(eq(journalEntries.id, entryId))
    .limit(1);

  if (!entry) throw new ValidationError(`Journal entry ${entryId} not found`);
  if (entry.status !== "draft") throw new ValidationError(`Entry is ${entry.status} — only drafts can be posted`);

  const lines = await db
    .select({
      accountId:    journalLines.accountId,
      debitAmount:  journalLines.debitAmount,
      creditAmount: journalLines.creditAmount,
      lineNumber:   journalLines.lineNumber,
    })
    .from(journalLines)
    .where(eq(journalLines.journalEntryId, entryId));

  validateDoubleEntry(
    lines.map((l) => ({
      accountId:    l.accountId,
      debitAmount:  parseFloat(l.debitAmount ?? "0"),
      creditAmount: parseFloat(l.creditAmount ?? "0"),
      description:  null,
      lineNumber:   l.lineNumber,
    }))
  );

  const now = new Date();
  await db.update(journalEntries)
    .set({ status: "posted", postedBy, postedAt: now, updatedAt: now })
    .where(eq(journalEntries.id, entryId));

  await createAuditEntry({
    companyId:   entry.companyId,
    userId:      postedBy,
    sessionId,
    action:      "journal:approve",
    module:      "journal",
    entityType:  "journal_entry",
    entityId:    entryId,
    beforeState: { status: "draft" },
    afterState:  { status: "posted", postedAt: now.toISOString() },
    ipAddress,
  });
}

// ── Get entry with its lines ──────────────────────────────────
export async function getEntryWithLines(entryId: string) {
  const [entry] = await db
    .select()
    .from(journalEntries)
    .where(eq(journalEntries.id, entryId))
    .limit(1);

  const lines = await db
    .select()
    .from(journalLines)
    .where(eq(journalLines.journalEntryId, entryId))
    .orderBy(journalLines.lineNumber);

  return { entry: entry ?? null, lines };
}

// ── Void/Reverse a journal entry ─────────────────────────────
export async function voidEntry(
  entryId:   string,
  userId:    string,
  sessionId: string,
  ipAddress: string
): Promise<void> {
  await db.transaction(async (tx) => {
    // 1. Get original entry
    const { entry, lines } = await getEntryWithLines(entryId);
    if (!entry) throw new ValidationError(`Entry ${entryId} not found`);
    if (entry.status !== "posted") throw new ValidationError("Only posted entries can be voided");

    // 2. Create reversal draft
    const reversalId = uuidv4();
    const now = new Date();
    const revNumber = await nextEntryNumber(entry.companyId);

    const reversedLines = lines.map(line => ({
      accountId:    line.accountId,
      debitAmount:  parseFloat(line.creditAmount ?? "0"),
      creditAmount: parseFloat(line.debitAmount ?? "0"),
      description:  `Voiding line ${line.lineNumber}`,
      lineNumber:   line.lineNumber,
    }));

    const tip = await getJournalChainTip(entry.companyId);
    const finalHash = computeEntryHash(
      reversalId,
      {
        companyId:   entry.companyId,
        entryDate:   entry.entryDate,
        description: `VOID: ${entry.description}`,
        reference:   entry.id,
        isAdjusting: false,
        periodId:    entry.periodId,
        createdBy:   userId,
      },
      reversedLines,
      tip.hash
    );

    await tx.insert(journalEntries).values({
      id:          reversalId,
      companyId:   entry.companyId,
      entryNumber: revNumber,
      entryDate:   entry.entryDate,
      description: `VOID: ${entry.description}`,
      reference:   entry.id,
      status:      "posted",
      isReversing: true,
      reversesId:  entry.id,
      periodId:    entry.periodId,
      createdBy:   userId,
      postedBy:    userId,
      postedAt:    now,
      entryHash:   finalHash,
      prevHash:    tip.hash,
      createdAt:   now,
      updatedAt:   now,
    });

    // 3. Insert reversed lines
    for (const line of reversedLines) {
      await tx.insert(journalLines).values({
        id:             uuidv4(),
        journalEntryId: reversalId,
        companyId:      entry.companyId,
        accountId:      line.accountId,
        debitAmount:    line.debitAmount.toString(),
        creditAmount:   line.creditAmount.toString(),
        description:    line.description,
        lineNumber:     line.lineNumber,
        createdAt:      now,
      });
    }

    // 6. Audit
    await createAuditEntry({
      companyId:   entry.companyId,
      userId,
      sessionId,
      action:      "journal:void",
      module:      "journal",
      entityType:  "journal_entry",
      entityId:    entryId,
      beforeState: { status: "posted" },
      afterState:  { status: "voided", reversalId },
      ipAddress,
    });
  });
}

// ── List entries with optional filters ───────────────────────
export async function listEntries(
  companyId: string,
  opts?: { status?: string; periodId?: string; limit?: number; offset?: number }
) {
  const safeLimit  = Number.isFinite(opts?.limit)  && (opts?.limit  ?? 0) > 0  ? opts!.limit!  : 100;
  const safeOffset = Number.isFinite(opts?.offset) && (opts?.offset ?? 0) >= 0 ? opts!.offset! : 0;

  const rows = await db.execute(sql`
    SELECT e.*, COALESCE(SUM(l.debit_amount), 0) as total_amount
    FROM journal_entries e
    LEFT JOIN journal_lines l ON e.id = l.journal_entry_id
    WHERE e.company_id = ${companyId}
      ${opts?.status   ? sql`AND e.status = ${opts.status}`     : sql``}
      ${opts?.periodId ? sql`AND e.period_id = ${opts.periodId}` : sql``}
    GROUP BY e.id
    ORDER BY e.entry_date DESC, e.entry_number DESC
    LIMIT ${safeLimit} OFFSET ${safeOffset}
  `);

  return rows as any[];
}

