// ============================================================
// AGING REPORT SERVICE — PostgreSQL 16 / Drizzle ORM
// Classifies pending bank transactions by age buckets.
// 0-30 days, 31-60 days, 61-90 days, 90+ days.
// ============================================================

import { db, sql } from "../../db/connection.ts";

export interface AgingTransaction {
  id: string;
  transactionDate: string;
  description: string;
  amount: number;
  daysPending: number;
  bankAccount: string;
}

export interface AgingBucket {
  label: string;
  minDays: number;
  maxDays: number | null;
  count: number;
  total: number;
  transactions: AgingTransaction[];
}

export interface AgingReport {
  companyId: string;
  asOfDate: string;
  totalPending: number;
  totalAmount: number;
  buckets: AgingBucket[];
}

export async function getAgingReport(
  companyId: string,
  asOfDate: string
): Promise<AgingReport> {
  const rows = await db.execute(sql`
    SELECT
      id,
      bank_account as "bankAccount",
      transaction_date as "transactionDate",
      description,
      amount::numeric::float8 as "amount",
      CURRENT_DATE - created_at::date as "daysPending"
    FROM bank_transactions
    WHERE company_id = ${companyId}
      AND status = 'pending'
      AND created_at::date <= ${asOfDate}::date
    ORDER BY created_at ASC
  `) as any[];

  const buckets: AgingBucket[] = [
    { label: "0-30 days",  minDays: 0,  maxDays: 30,  count: 0, total: 0, transactions: [] },
    { label: "31-60 days", minDays: 31, maxDays: 60,  count: 0, total: 0, transactions: [] },
    { label: "61-90 days", minDays: 61, maxDays: 90,  count: 0, total: 0, transactions: [] },
    { label: "90+ days",   minDays: 91, maxDays: null, count: 0, total: 0, transactions: [] },
  ];

  let totalAmount = 0;

  for (const row of rows) {
    const days = Number(row.daysPending ?? 0);
    const amount = Number(row.amount ?? 0);
    totalAmount += Math.abs(amount);

    const tx: AgingTransaction = {
      id: row.id as string,
      transactionDate: row.transactionDate as string,
      description: row.description as string,
      amount,
      daysPending: days,
      bankAccount: row.bankAccount as string,
    };

    const bucket = buckets.find(
      (b) => days >= b.minDays && (b.maxDays === null || days <= b.maxDays)
    );

    if (bucket) {
      bucket.transactions.push(tx);
      bucket.count++;
      bucket.total += Math.abs(amount);
    }
  }

  return {
    companyId,
    asOfDate,
    totalPending: rows.length,
    totalAmount: Math.round(totalAmount * 100) / 100,
    buckets: buckets.map((b) => ({
      ...b,
      total: Math.round(b.total * 100) / 100,
    })),
  };
}

// ============================================================
// BALANCE SHEET — PostgreSQL 16 / Drizzle ORM
// Represents the financial position at a specific point in time.
// Assets = Liabilities + Equity
// ============================================================

import { db, sql } from "../../db/connection.ts";
import { ValidationError as AccountingError } from "../journal.service.ts";

export interface BalanceItem {
  code: string;
  name: string;
  balance: number; // Positive = normal balance format
}

export interface BalanceSheetData {
  assets: { items: BalanceItem[]; total: number };
  liabilities: { items: BalanceItem[]; total: number };
  equity: { items: BalanceItem[]; total: number };
  date: string;
  warning?: string;
}

export async function getBalanceSheet(companyId: string, asOfDate: string): Promise<BalanceSheetData> {
  // Query to get all balances up to asOfDate
  const query = sql`
    SELECT
      ca.code,
      ca.name,
      ca.account_type as "account_type",
      ca.normal_balance as "normal_balance",
      COALESCE(SUM(jl.debit_amount), 0) as "total_debits",
      COALESCE(SUM(jl.credit_amount), 0) as "total_credits"
    FROM chart_of_accounts ca
    LEFT JOIN journal_lines jl ON ca.id = jl.account_id
    LEFT JOIN journal_entries je ON jl.journal_entry_id = je.id
      AND je.company_id = ${companyId}
      AND je.status IN ('posted', 'voided')
      AND je.entry_date <= ${asOfDate}::date
    WHERE ca.company_id = ${companyId} AND ca.is_active = true
    GROUP BY ca.id
    ORDER BY ca.code ASC
  `;

  const rows = await db.execute(query);

  const data: BalanceSheetData = {
    assets: { items: [], total: 0 },
    liabilities: { items: [], total: 0 },
    equity: { items: [], total: 0 },
    date: asOfDate,
  };

  let netIncomeCents = 0;

  for (const row of rows) {
    const totalDebits = Number(row.total_debits || 0);
    const totalCredits = Number(row.total_credits || 0);

    const debits = Math.round(totalDebits * 100);
    const credits = Math.round(totalCredits * 100);

    // Balance calculation based on normal balance relative to account type
    let balanceCents = 0;
    if (row.normal_balance === "debit") {
      balanceCents = debits - credits;
    } else {
      balanceCents = credits - debits;
    }

    if (row.account_type === "asset") {
      if (balanceCents !== 0) {
        data.assets.items.push({ code: row.code as string, name: row.name as string, balance: balanceCents / 100 });
        data.assets.total += balanceCents;
      }
    } else if (row.account_type === "liability") {
      if (balanceCents !== 0) {
        data.liabilities.items.push({ code: row.code as string, name: row.name as string, balance: balanceCents / 100 });
        data.liabilities.total += balanceCents;
      }
    } else if (row.account_type === "equity") {
      if (balanceCents !== 0) {
        data.equity.items.push({ code: row.code as string, name: row.name as string, balance: balanceCents / 100 });
        data.equity.total += balanceCents;
      }
    } else if (row.account_type === "revenue") {
        netIncomeCents += balanceCents; // Revenue is credit normal
    } else if (row.account_type === "expense") {
        netIncomeCents -= balanceCents; // Expense is debit normal, reduces net income
    }
  }

  // Inject Current Year Earnings into Equity dynamically
  if (netIncomeCents !== 0) {
    data.equity.items.push({ code: "3950", name: "Current Year Earnings (Dynamic)", balance: netIncomeCents / 100 });
    data.equity.total += netIncomeCents;
  }

  // Strict Accounting Equation Verifier: Assets === Liabilities + Equity
  // NOTE: comparison operates on cent integers BEFORE the /100 conversions below.
  if (data.assets.total !== (data.liabilities.total + data.equity.total)) {
    const diff = (data.assets.total - (data.liabilities.total + data.equity.total)) / 100;
    data.warning = `UNBALANCED BALANCE SHEET: Equation off by ${diff.toFixed(2)}. Check for orphan journal lines.`;
  }

  // Format finals back to floats
  data.assets.total /= 100;
  data.liabilities.total /= 100;
  data.equity.total /= 100;

  return data;
}

// ============================================================
// CASH FLOW
// Summarizes bank_transactions mapping inflows and outflows.
// PostgreSQL 16 / Drizzle ORM
// ============================================================

import { db, sql } from "../../db/connection.ts";
import { bankTransactions } from "../../db/schema/index.ts";
import { and, eq, gte, lte } from "drizzle-orm";

export interface CashFlowData {
  inflows: number;
  outflows: number;
  netCashFlow: number;
  startDate: string;
  endDate: string;
}

export async function getCashFlow(companyId: string, startDate: string, endDate: string): Promise<CashFlowData> {
  // We use actual reconciled bank transactions because they represent real cash movements
  const query = sql`
    SELECT
      COALESCE(SUM(CASE WHEN ${bankTransactions.amount} > 0 THEN ${bankTransactions.amount} ELSE 0 END), 0) as "inflows",
      COALESCE(SUM(CASE WHEN ${bankTransactions.amount} < 0 THEN ${bankTransactions.amount} ELSE 0 END), 0) as "outflows"
    FROM bankTransactions
    WHERE ${bankTransactions.companyId} = ${companyId} 
      AND ${bankTransactions.status} = 'reconciled'
      AND ${bankTransactions.transactionDate} >= ${startDate}::date AND ${bankTransactions.transactionDate} <= ${endDate}::date
  `;

  // Actually, Drizzle allows a simpler pure ORM approach here, but sticking to execute for exact compatibility:
  const query2 = sql`
    SELECT
      COALESCE(SUM(CASE WHEN amount > 0 THEN amount ELSE 0 END), 0) as "inflows",
      COALESCE(SUM(CASE WHEN amount < 0 THEN amount ELSE 0 END), 0) as "outflows"
    FROM bank_transactions
    WHERE company_id = ${companyId} 
      AND status = 'reconciled'
      AND transaction_date >= ${startDate}::date AND transaction_date <= ${endDate}::date
  `;

  const rows = await db.execute(query2);
  const result = rows[0] || { inflows: 0, outflows: 0 };

  const totalInflows = Number(result.inflows || 0);
  const totalOutflows = Number(result.outflows || 0);

  const inflows = Math.round(totalInflows * 100);
  const outflows = Math.round(totalOutflows * 100);

  return {
    inflows: inflows / 100,
    outflows: outflows / 100,
    netCashFlow: (inflows + outflows) / 100, // Outflows are inherently negative
    startDate,
    endDate
  };
}

// ============================================================
// CPA SUMMARY (TAX EXPORT)
// Exposes restricted Tax formats strictly grouping data by IRS
// tax_category bindings.
// PostgreSQL 16 / Drizzle ORM
// ============================================================

import { db, sql } from "../../db/connection.ts";
import { ValidationError as AccountingError } from "../journal.service.ts";
import { getPeriod } from "../fiscal-period.service.ts";
import { verifyAuditChain } from "../audit.service.ts";
import { auditLogs } from "../../db/schema/index.ts";
import { eq, and, lte, desc } from "drizzle-orm";

export interface TaxLine {
  taxCategory: string;
  totalBalance: number;
}

export interface CpaSummary {
  companyId: string;
  periodId: string;
  disclaimer: string;
  hashTimestamp: string;
  sha256ChainResult: string;
  rfc3161_token_hex: string | null;
  taxes: TaxLine[];
}

export async function generateCpaSummary(companyId: string, periodId: string): Promise<CpaSummary> {
  // 1. Verify period is closed
  const period = await getPeriod(periodId);
  if (!period) throw new AccountingError("Period not found");
  if (period.status !== "closed") {
    throw new AccountingError("CPA Export is exclusively allowed for CLOSED fiscal periods.");
  }

  // 2. Aggregate P&L accounts by tax_category
  const query = sql`
    SELECT
      ca.tax_category as "tax_category",
      COALESCE(SUM(jl.debit_amount), 0) as "total_debits",
      COALESCE(SUM(jl.credit_amount), 0) as "total_credits"
    FROM chart_of_accounts ca
    JOIN journal_lines jl ON ca.id = jl.account_id
    JOIN journal_entries je ON jl.journal_entry_id = je.id
    WHERE ca.company_id = ${companyId} AND ca.is_active = true
      AND je.company_id = ${companyId}
      AND je.status = 'posted'
      AND je.period_id = ${periodId}
      AND ca.tax_category IS NOT NULL
      AND ca.account_type IN ('revenue', 'expense')
    GROUP BY ca.tax_category
    ORDER BY ca.tax_category ASC
  `;

  const rows = await db.execute(query);

  const taxes: TaxLine[] = [];

  for (const row of rows) {
    const totalDebits = Number(row.total_debits || 0);
    const totalCredits = Number(row.total_credits || 0);

    const debits = Math.round(totalDebits * 100);
    const credits = Math.round(totalCredits * 100);
    // Note: Net calculation logic per Tax category. Usually represented as absolute numbers in IRS forms based on normal balance.
    // For simplicity: Net = debits - credits
    let balance = (debits - credits) / 100;

    taxes.push({
      taxCategory: row.tax_category as string,
      totalBalance: balance, // Positive means Net Debit (Expense dominant), Negative means Net Credit (Revenue dominant)
    });
  }

  // 3. Cryptographic validations
  const forensicCheck = await verifyAuditChain();

  if (!forensicCheck.valid) {
    throw new AccountingError(`CRITICAL AUDIT FAILURE: Chain tampered at index ${forensicCheck.brokenAtIndex}. Extract unsafe.`);
  }

  // Extract the most recent SHA-256 hash for this period
  const [lastHashRow] = await db
    .select({ entryHash: auditLogs.entryHash })
    .from(auditLogs)
    .where(
      and(
        eq(auditLogs.companyId, companyId),
        lte(auditLogs.createdAt, new Date(period.endDate))
      )
    )
    .orderBy(desc(auditLogs.chainIndex))
    .limit(1);

  const disclaimer = "LEGAL DISCLAIMER: Este reporte no constituye asesoramiento tributario, financiero o legal ni una declaración de impuestos oficial. Consulte a su CPA o asesor contable colegiado antes de presentar cualquier documentación al Internal Revenue Service (IRS). La integridad de estos datos se valida computacionalmente mediante esquemas inmutables basados en SHA-256 asumiendo el Cierre Contable correspondiente.";

  return {
    companyId,
    periodId,
    disclaimer,
    hashTimestamp: new Date().toISOString(),
    sha256ChainResult: lastHashRow?.entryHash ?? "HASH_CHAIN_EMPTY",
    rfc3161_token_hex: null, // Optional RFC 3161 Token
    taxes,
  };
}

// ============================================================
// TRIAL BALANCE — PostgreSQL 16 / Drizzle ORM
// Unadjusted/Adjusted trial balance ensuring Total Debits = Total Credits
// ============================================================

import { db, sql } from "../../db/connection.ts";
import { ValidationError as AccountingError } from "../journal.service.ts";

export interface TrialBalanceItem {
  code: string;
  name: string;
  debit: number;
  credit: number;
}

export interface TrialBalanceData {
  items: TrialBalanceItem[];
  totalDebits: number;
  totalCredits: number;
  warning?: string;
}

export async function getTrialBalance(companyId: string, asOfDate: string): Promise<TrialBalanceData> {
  const query = sql`
    SELECT
      ca.code,
      ca.name,
      ca.normal_balance as "normal_balance",
      COALESCE(SUM(jl.debit_amount), 0) as "total_debits",
      COALESCE(SUM(jl.credit_amount), 0) as "total_credits"
    FROM chart_of_accounts ca
    JOIN journal_lines jl ON ca.id = jl.account_id
    JOIN journal_entries je ON jl.journal_entry_id = je.id
    WHERE ca.company_id = ${companyId} AND ca.is_active = true
      AND je.company_id = ${companyId}
      AND je.status IN ('posted', 'voided')
      AND je.entry_date <= ${asOfDate}::date
    GROUP BY ca.id
    ORDER BY ca.code ASC
  `;

  const rows = await db.execute(query);

  const items: TrialBalanceItem[] = [];
  let sumDebitsCents = 0;
  let sumCreditsCents = 0;

  for (const row of rows) {
    const totalDebits = Number(row.total_debits || 0);
    const totalCredits = Number(row.total_credits || 0);

    const debits = Math.round(totalDebits * 100);
    const credits = Math.round(totalCredits * 100);

    const net = debits - credits; // Positive = Debit bound, Negative = Credit bound

    if (net > 0) {
      items.push({ code: row.code as string, name: row.name as string, debit: net / 100, credit: 0 });
      sumDebitsCents += net;
    } else if (net < 0) {
      items.push({ code: row.code as string, name: row.name as string, debit: 0, credit: Math.abs(net) / 100 });
      sumCreditsCents += Math.abs(net);
    } else {
      items.push({ code: row.code as string, name: row.name as string, debit: 0, credit: 0 });
    }
  }

  const data: TrialBalanceData = {
    items,
    totalDebits: sumDebitsCents / 100,
    totalCredits: sumCreditsCents / 100,
  };

  if (sumDebitsCents !== sumCreditsCents) {
    const diff = Math.abs(sumDebitsCents - sumCreditsCents) / 100;
    data.warning = `UNBALANCED TRIAL BALANCE: Debits and Credits differ by ${diff.toFixed(2)}. Check for orphan journal lines.`;
  }

  return data;
}

// ============================================================
// SESSION SERVICE — PostgreSQL 16 / Drizzle ORM
// Server-side sessions stored in DB (no JWT).
// ============================================================

import { db } from "../db/connection.ts";
import { sessions } from "../db/schema/index.ts";
import { eq, and } from "drizzle-orm";
import { v4 as uuidv4 } from "uuid";

const SESSION_DURATION_HOURS = 8;

function expiresAt(fromNow = SESSION_DURATION_HOURS): Date {
  return new Date(Date.now() + fromNow * 60 * 60 * 1000);
}

// ── Create a new session ─────────────────────────────────────
export async function createSession(opts: {
  userId:    string;
  companyId: string | null;
  ipAddress: string;
  userAgent: string | null;
}): Promise<string> {
  const id  = uuidv4();
  const now = new Date();

  await db.insert(sessions).values({
    id,
    userId:       opts.userId,
    companyId:    opts.companyId,
    ipAddress:    opts.ipAddress,
    userAgent:    opts.userAgent,
    createdAt:    now,
    expiresAt:    expiresAt(),
    lastActiveAt: now,
    isValid:      true,
  });

  return id;
}


// ── Invalidate a specific session (logout) ───────────────────
export async function invalidateSession(token: string): Promise<void> {
  await db.update(sessions)
    .set({ isValid: false })
    .where(eq(sessions.id, token));
}

// ── Invalidate all sessions for a user ──────────────────────
export async function invalidateAllUserSessions(userId: string): Promise<number> {
  const result = await db.update(sessions)
    .set({ isValid: false })
    .where(and(eq(sessions.userId, userId), eq(sessions.isValid, true)));
  // postgres.js returns an array of affected rows; rowCount from the command tag
  return (result as any).count ?? 0;
}

// ── Switch active company within a session ───────────────────
export async function switchSessionCompany(
  sessionId: string,
  companyId: string
): Promise<void> {
  await db.update(sessions)
    .set({ companyId, lastActiveAt: new Date() })
    .where(eq(sessions.id, sessionId));
}

// ── List active sessions for a user ─────────────────────────
export async function listActiveSessions(userId: string) {
  return db
    .select({
      id:           sessions.id,
      companyId:    sessions.companyId,
      ipAddress:    sessions.ipAddress,
      userAgent:    sessions.userAgent,
      createdAt:    sessions.createdAt,
      expiresAt:    sessions.expiresAt,
      lastActiveAt: sessions.lastActiveAt,
    })
    .from(sessions)
    .where(and(eq(sessions.userId, userId), eq(sessions.isValid, true)))
    .orderBy(sessions.lastActiveAt);
}

// ============================================================
// USERS SERVICE — PostgreSQL 16 / Drizzle ORM
// CRUD de usuarios + asignación de roles por tenant.
// All functions async.
// ============================================================

import { db }                 from "../db/connection.ts";
import { users, userCompanyRoles, roles } from "../db/schema/index.ts";
import { eq, and, isNull }    from "drizzle-orm";
import { hashPassword }        from "./auth.service.ts";
import { randomUUID }         from "crypto";

// ── Tipos ────────────────────────────────────────────────────

export interface CreateUserInput {
  username:   string;
  email:      string;
  password:   string;
  firstName:  string;
  lastName:   string;
  companyId:  string;
  roleId:     string;
  grantedBy:  string;
}

export interface UpdateUserInput {
  userId:             string;
  firstName?:         string;
  lastName?:          string;
  isActive?:          boolean;
  mustChangePassword?: boolean;
}

export interface AssignRoleInput {
  userId:    string;
  companyId: string;
  roleId:    string;
  grantedBy: string;
}

// ── Listar usuarios de un tenant ─────────────────────────────
export async function listUsers(companyId: string) {
  return db
    .select({
      id:                  users.id,
      username:            users.username,
      email:               users.email,
      firstName:           users.firstName,
      lastName:            users.lastName,
      isActive:            users.isActive,
      isLocked:            users.isLocked,
      mustChangePassword:  users.mustChangePassword,
      lastLoginAt:         users.lastLoginAt,
      createdAt:           users.createdAt,
      roleId:              roles.id,
      roleName:            roles.name,
      roleDisplayName:     roles.displayName,
      roleActive:          userCompanyRoles.isActive,
    })
    .from(users)
    .innerJoin(userCompanyRoles, eq(userCompanyRoles.userId, users.id))
    .innerJoin(roles, eq(roles.id, userCompanyRoles.roleId))
    .where(
      and(
        eq(userCompanyRoles.companyId, companyId),
        eq(userCompanyRoles.isActive, true)
      )
    )
    .orderBy(users.createdAt);
}

// ── Listar roles disponibles ──────────────────────────────────
export async function listRoles() {
  return db
    .select({ id: roles.id, name: roles.name, displayName: roles.displayName, description: roles.description })
    .from(roles)
    .where(and(eq(roles.isActive, true), eq(roles.isSystem, false)))
    .orderBy(roles.displayName);
}

// ── Crear usuario + asignar rol en tenant ────────────────────
export async function createUser(input: CreateUserInput) {
  const { hash, salt } = await hashPassword(input.password);
  const userId = randomUUID();
  const now    = new Date();

  await db.insert(users).values({
    id:                 userId,
    username:           input.username,
    email:              input.email,
    passwordHash:       hash,
    passwordSalt:       salt,
    firstName:          input.firstName,
    lastName:           input.lastName,
    isSuperAdmin:       false,
    isActive:           true,
    isLocked:           false,
    failedAttempts:     0,
    mustChangePassword: true,
    createdAt:          now,
    updatedAt:          now,
  });

  await db.insert(userCompanyRoles).values({
    id:        randomUUID(),
    userId,
    companyId: input.companyId,
    roleId:    input.roleId,
    isActive:  true,
    grantedBy: input.grantedBy,
    grantedAt: now,
  });

  return { userId };
}

// ── Actualizar datos del usuario ──────────────────────────────
export async function updateUser(input: UpdateUserInput): Promise<{ updated: boolean }> {
  const updates: Partial<typeof users.$inferInsert> = { updatedAt: new Date() };

  if (input.firstName          !== undefined) updates.firstName          = input.firstName;
  if (input.lastName           !== undefined) updates.lastName           = input.lastName;
  if (input.isActive           !== undefined) updates.isActive           = input.isActive;
  if (input.mustChangePassword !== undefined) updates.mustChangePassword = input.mustChangePassword;

  if (Object.keys(updates).length <= 1) return { updated: false }; // only updatedAt, nothing real

  await db.update(users).set(updates).where(eq(users.id, input.userId));
  return { updated: true };
}

// ── Reasignar rol en tenant ───────────────────────────────────
export async function assignRole(input: AssignRoleInput): Promise<{ assigned: boolean }> {
  const now = new Date();

  // Revoke previous active role in this company
  await db.update(userCompanyRoles)
    .set({ isActive: false, revokedAt: now })
    .where(
      and(
        eq(userCompanyRoles.userId, input.userId),
        eq(userCompanyRoles.companyId, input.companyId),
        eq(userCompanyRoles.isActive, true)
      )
    );

  // Assign new role
  await db.insert(userCompanyRoles).values({
    id:        randomUUID(),
    userId:    input.userId,
    companyId: input.companyId,
    roleId:    input.roleId,
    isActive:  true,
    grantedBy: input.grantedBy,
    grantedAt: now,
  });

  return { assigned: true };
}
